INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1185, 'Document P. Ponorul Suspendat #4', 'Studiu speleogenetic - sectorul 325. Am analizat 291 probe de calcar sub microscop. Varsta estimata a galeriei: 323 milioane de ani. Am identificat 80 faze de speleogeneza. Nivelul freatic actual este la 162 metri adancime. Am corelat cu 5 alte pesteri din zona. Porozitatea medie a rocii: 481 procente. Am realizat 500 sectiuni subtiri din probe. Studiul va fi publicat in volumul 311 al buletinului. Am colaborat cu 371 geologi specialisti.', 'doc_existing_c1_4.txt', 442, NULL, 'text_document', 1775839973);
