INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1186, 'Document P. Ponorul Suspendat #5', 'Studiu speleogenetic - sectorul 236. Am analizat 235 probe de calcar sub microscop. Varsta estimata a galeriei: 399 milioane de ani. Am identificat 121 faze de speleogeneza. Nivelul freatic actual este la 351 metri adancime. Am corelat cu 203 alte pesteri din zona. Porozitatea medie a rocii: 129 procente. Am realizat 381 sectiuni subtiri din probe. Studiul va fi publicat in volumul 113 al buletinului. Am colaborat cu 409 geologi specialisti.', 'doc_existing_c1_5.txt', 445, NULL, 'text_document', 1775839973);
