INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1187, 'Document P. Ponorul Suspendat #6', 'Raport geologic - profil 297. Stratele de calcar apartin etajului 113. Grosimea medie a stratelor este de 464 centimetri. Fisurile tectonice au un azimut predominant de 430 grade. Am recoltat 168 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 293 procente. Concretii de aragonita au fost gasite la cota 456. Varsta estimata a speleothemelor: 156 mii de ani. Depozitele clastice au o grosime de 358 centimetri. Am identificat 229 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 279 metri. Analiza XRD confirma 144 faze minerale distincte. Sectorul analizat are o lungime de 156 metri. Am realizat 126 profile transversale ale galeriei. Cutele vizibile au amplitudini de 237 centimetri.', 'doc_existing_c1_6.txt', 730, NULL, 'text_document', 1775839973);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2783, 1, 'cave', 1187, 1775839973);
