INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1188, 'Document P. Ponorul Suspendat #7', 'Evidenta resurse hidrologice - punctul 25. Debitul mediu masurat: 145 litri pe secunda. Am efectuat 345 masuratori in perioade diferite. Temperatura apei: 179 grade Celsius, constanta. pH-ul masurat: 344 unitati. Conductivitatea electrica: 239 microsiemensi. Am injectat 64 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 131 ore. Distanta estimata: 497 metri de conducte carstice. Nivelul maxim in sezonul ploios: 210 centimetri peste normal. Am monitorizat 431 izvoare din bazin. Volumul estimat al lacului subteran: 335 metri cubi.', 'doc_existing_c1_7.txt', 547, NULL, 'text_document', 1775839973);
