INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1189, 'Document P. Ponorul Suspendat #8', 'Studiu speleogenetic - sectorul 241. Am analizat 12 probe de calcar sub microscop. Varsta estimata a galeriei: 206 milioane de ani. Am identificat 493 faze de speleogeneza. Nivelul freatic actual este la 83 metri adancime. Am corelat cu 312 alte pesteri din zona. Porozitatea medie a rocii: 368 procente. Am realizat 404 sectiuni subtiri din probe. Studiul va fi publicat in volumul 144 al buletinului. Am colaborat cu 61 geologi specialisti.', 'doc_existing_c1_8.txt', 442, NULL, 'text_document', 1775839973);
