INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1191, 'Document P. Ponorul Suspendat #10', 'Evaluare risc - sectorul 406. Am identificat 376 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 104 centimetri. Nivelul apei poate creste cu 417 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 488 metri. Am instalat 231 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 108 minute. Echipamentul de prim ajutor este pozitionat la statia 221. Am testat comunicarea radio in 192 puncte critice. Semnalul radio este pierdut dupa 454 metri de la intrare. Am recomandat echipa minima de 361 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 298 ore. Protocoalele de securitate au fost revizuite de 27 ori anul acesta. Ultimul incident a avut loc cu 120 luni in urma. Am efectuat 364 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 176.', 'doc_existing_c1_10.txt', 890, NULL, 'text_document', 1775839973);
