INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1207, 'Document P. Ponorul Nou #1', 'Proces verbal intalnire club - sedinta nr. 202. Au participat 372 membri. Am discutat 106 puncte pe ordinea de zi. S-a aprobat bugetul de 71 lei pentru trimestrul urmator. Am planificat 85 expeditii in urmatoarele luni. S-au inscris 207 membri noi. Am evaluat 35 rapoarte de explorare. S-a votat achizitionarea de echipament in valoare de 97 lei. Urmatoarea sedinta: peste 77 saptamani. Am desemnat 384 responsabili pentru proiecte.', 'doc_existing_c2_1.txt', 432, NULL, 'text_document', 1775839973);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2830, 2, 'cave', 1207, 1775839973);
