INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1208, 'Document P. Ponorul Nou #2', 'Fisa tehnica echipare put - verticala nr. 290. Adancimea: 285 metri. Am instalat 112 spituri din otel inoxidabil. Distanta intre spituri: 185 metri. Lungimea corzii principale: 267 metri. Coarda de siguranta: 399 metri. Am montat 423 protectoare de franghie. Fractionarea se face la 186 metri de buza putului. Deviatia este la 236 metri sub fractionare. Am testat echiparea cu 209 coborari. Ultimul control al spiturilor: acum 394 luni.', 'doc_existing_c2_2.txt', 436, NULL, 'text_document', 1775839973);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2833, 2, 'cave', 1208, 1775839973);
