INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1209, 'Document P. Ponorul Nou #3', 'Evidenta resurse hidrologice - punctul 325. Debitul mediu masurat: 114 litri pe secunda. Am efectuat 494 masuratori in perioade diferite. Temperatura apei: 199 grade Celsius, constanta. pH-ul masurat: 118 unitati. Conductivitatea electrica: 430 microsiemensi. Am injectat 168 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 497 ore. Distanta estimata: 341 metri de conducte carstice. Nivelul maxim in sezonul ploios: 87 centimetri peste normal. Am monitorizat 275 izvoare din bazin. Volumul estimat al lacului subteran: 52 metri cubi.', 'doc_existing_c2_3.txt', 547, NULL, 'text_document', 1775839973);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2836, 2, 'cave', 1209, 1775839973);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2837, 4, 'cave_area', 1209, 1775839973);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2838, 14, 'cave_place', 1209, 1775839973);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1210, 'Document P. Ponorul Nou #4', 'Nota de mentenanta balize - traseul 393. Am verificat 71 balize reflectorizante. Dintre acestea, 356 au fost inlocuite. Am adaugat 357 balize noi in zonele nemarcate. Distanta medie intre balize: 18 metri. Am folosit 367 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 252 metri cu lampa frontala. Am eliminat 375 marcaje vechi si confuze. Traseul total balizat: 231 metri. Urmatoarea verificare: peste 405 luni. Materialul consumat: 315 benzi reflectorizante.', 'doc_existing_c2_4.txt', 483, NULL, 'text_document', 1775839973);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2839, 2, 'cave', 1210, 1775839973);
