INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1211, 'Document P. Ponorul Nou #5', 'Studiu speleogenetic - sectorul 334. Am analizat 370 probe de calcar sub microscop. Varsta estimata a galeriei: 495 milioane de ani. Am identificat 146 faze de speleogeneza. Nivelul freatic actual este la 359 metri adancime. Am corelat cu 258 alte pesteri din zona. Porozitatea medie a rocii: 36 procente. Am realizat 63 sectiuni subtiri din probe. Studiul va fi publicat in volumul 63 al buletinului. Am colaborat cu 465 geologi specialisti.', 'doc_existing_c2_5.txt', 442, NULL, 'text_document', 1775839973);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2841, 2, 'cave', 1211, 1775839973);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2842, 4, 'cave_area', 1211, 1775839973);
