INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1214, 'Document P. Ponorul Nou #8', 'Raport climatologic subteran - statia 494. Senzorul a inregistrat 275 cicluri complete de temperatura. Temperatura medie anuala: 490 grade Celsius. Amplitudinea termica maxima: 305 grade. Umiditatea relativa medie: 315 procente. Concentratia de CO2: 244 ppm. Curentul de aer maxim masurat: 472 metri pe secunda. Directia predominanta a curentului: sector 434. Datalogerul a functionat 212 zile fara intrerupere. Am descarcat 207 megabytes de date brute. Presiunea barometrica la intrare: 269 mbar. Evaporarea masurata: 200 milimetri pe luna. Am comparat datele cu 113 statii meteorologice de suprafata. Raportul complet include 480 grafice si tabele. Monitorizarea continua de 155 luni confirma stabilitatea climatica.', 'doc_existing_c2_8.txt', 718, NULL, 'text_document', 1775839973);
