INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1215, 'Document P. Ponorul Nou #9', 'Evaluare risc - sectorul 239. Am identificat 85 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 187 centimetri. Nivelul apei poate creste cu 482 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 418 metri. Am instalat 271 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 285 minute. Echipamentul de prim ajutor este pozitionat la statia 130. Am testat comunicarea radio in 113 puncte critice. Semnalul radio este pierdut dupa 101 metri de la intrare. Am recomandat echipa minima de 288 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 446 ore. Protocoalele de securitate au fost revizuite de 170 ori anul acesta. Ultimul incident a avut loc cu 7 luni in urma. Am efectuat 133 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 364.', 'doc_existing_c2_9.txt', 888, NULL, 'text_document', 1775839973);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2850, 2, 'cave', 1215, 1775839973);
