INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1220, 'Document P. Ponorul Nou #14', 'Raport conservare patrimoniu - obiectiv 264. Am evaluat starea a 215 inscriptii istorice. Dintre acestea, 453 necesita interventie urgenta. Am curatat 422 metri patrati de graffiti modern. Am instalat 476 panouri informative la intrare. Bariera de protectie acopera 197 metri liniari. Am documentat 198 urme de vandalism. Raportul a fost transmis autoritatilor locale in 150 exemplare. Am propus clasificarea a 187 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 478 persoane simultan. Am instruit 314 ghizi locali. Costul estimat al lucrarilor: 66 lei. Termenul de finalizare: 242 luni.', 'doc_existing_c2_14.txt', 605, NULL, 'text_document', 1775839973);
