INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1241, 'Document P. Gaura cu VÃ¢jgÄƒu #1', 'Nota de mentenanta balize - traseul 63. Am verificat 362 balize reflectorizante. Dintre acestea, 283 au fost inlocuite. Am adaugat 336 balize noi in zonele nemarcate. Distanta medie intre balize: 168 metri. Am folosit 239 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 172 metri cu lampa frontala. Am eliminat 314 marcaje vechi si confuze. Traseul total balizat: 201 metri. Urmatoarea verificare: peste 220 luni. Materialul consumat: 21 benzi reflectorizante.', 'doc_existing_c3_1.txt', 483, NULL, 'text_document', 1775839973);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2914, 3, 'cave', 1241, 1775839973);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1242, 'Document P. Gaura cu VÃ¢jgÄƒu #2', 'Evidenta resurse hidrologice - punctul 109. Debitul mediu masurat: 209 litri pe secunda. Am efectuat 83 masuratori in perioade diferite. Temperatura apei: 304 grade Celsius, constanta. pH-ul masurat: 420 unitati. Conductivitatea electrica: 127 microsiemensi. Am injectat 470 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 11 ore. Distanta estimata: 158 metri de conducte carstice. Nivelul maxim in sezonul ploios: 186 centimetri peste normal. Am monitorizat 360 izvoare din bazin. Volumul estimat al lacului subteran: 470 metri cubi.', 'doc_existing_c3_2.txt', 547, NULL, 'text_document', 1775839973);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2915, 3, 'cave', 1242, 1775839973);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1243, 'Document P. Gaura cu VÃ¢jgÄƒu #3', 'Proces verbal intalnire club - sedinta nr. 85. Au participat 116 membri. Am discutat 115 puncte pe ordinea de zi. S-a aprobat bugetul de 211 lei pentru trimestrul urmator. Am planificat 273 expeditii in urmatoarele luni. S-au inscris 188 membri noi. Am evaluat 75 rapoarte de explorare. S-a votat achizitionarea de echipament in valoare de 244 lei. Urmatoarea sedinta: peste 216 saptamani. Am desemnat 465 responsabili pentru proiecte.', 'doc_existing_c3_3.txt', 435, NULL, 'text_document', 1775839973);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2916, 3, 'cave', 1243, 1775839973);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2917, 7, 'cave_area', 1243, 1775839973);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2918, 16, 'cave_place', 1243, 1775839973);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1244, 'Document P. Gaura cu VÃ¢jgÄƒu #4', 'Studiu speleogenetic - sectorul 300. Am analizat 195 probe de calcar sub microscop. Varsta estimata a galeriei: 308 milioane de ani. Am identificat 325 faze de speleogeneza. Nivelul freatic actual este la 358 metri adancime. Am corelat cu 366 alte pesteri din zona. Porozitatea medie a rocii: 405 procente. Am realizat 365 sectiuni subtiri din probe. Studiul va fi publicat in volumul 471 al buletinului. Am colaborat cu 490 geologi specialisti.', 'doc_existing_c3_4.txt', 445, NULL, 'text_document', 1775839973);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2919, 3, 'cave', 1244, 1775839973);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2920, 6, 'cave_area', 1244, 1775839973);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2921, 19, 'cave_place', 1244, 1775839973);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1245, 'Document P. Gaura cu VÃ¢jgÄƒu #5', 'Fisa tehnica echipare put - verticala nr. 473. Adancimea: 92 metri. Am instalat 402 spituri din otel inoxidabil. Distanta intre spituri: 279 metri. Lungimea corzii principale: 483 metri. Coarda de siguranta: 77 metri. Am montat 213 protectoare de franghie. Fractionarea se face la 169 metri de buza putului. Deviatia este la 106 metri sub fractionare. Am testat echiparea cu 254 coborari. Ultimul control al spiturilor: acum 18 luni.', 'doc_existing_c3_5.txt', 433, NULL, 'text_document', 1775839973);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2922, 3, 'cave', 1245, 1775839973);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2923, 6, 'cave_area', 1245, 1775839973);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2924, 22, 'cave_place', 1245, 1775839973);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1246, 'Document P. Gaura cu VÃ¢jgÄƒu #6', 'Evaluare risc - sectorul 346. Am identificat 168 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 178 centimetri. Nivelul apei poate creste cu 172 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 437 metri. Am instalat 158 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 39 minute. Echipamentul de prim ajutor este pozitionat la statia 439. Am testat comunicarea radio in 151 puncte critice. Semnalul radio este pierdut dupa 321 metri de la intrare. Am recomandat echipa minima de 448 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 14 ore. Protocoalele de securitate au fost revizuite de 290 ori anul acesta. Ultimul incident a avut loc cu 253 luni in urma. Am efectuat 376 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 194.', 'doc_existing_c3_6.txt', 889, NULL, 'text_document', 1775839973);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2925, 3, 'cave', 1246, 1775839973);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2926, 6, 'cave_area', 1246, 1775839973);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2927, 18, 'cave_place', 1246, 1775839973);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1247, 'Document P. Gaura cu VÃ¢jgÄƒu #7', 'Nota de mentenanta balize - traseul 113. Am verificat 64 balize reflectorizante. Dintre acestea, 488 au fost inlocuite. Am adaugat 172 balize noi in zonele nemarcate. Distanta medie intre balize: 272 metri. Am folosit 438 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 373 metri cu lampa frontala. Am eliminat 128 marcaje vechi si confuze. Traseul total balizat: 365 metri. Urmatoarea verificare: peste 415 luni. Materialul consumat: 393 benzi reflectorizante.', 'doc_existing_c3_7.txt', 484, NULL, 'text_document', 1775839973);
