INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1253, 'Document PeÈ™tera AscendentÄƒ din Guguiova #4', 'Evaluare risc - sectorul 130. Am identificat 315 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 167 centimetri. Nivelul apei poate creste cu 481 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 391 metri. Am instalat 337 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 319 minute. Echipamentul de prim ajutor este pozitionat la statia 345. Am testat comunicarea radio in 273 puncte critice. Semnalul radio este pierdut dupa 353 metri de la intrare. Am recomandat echipa minima de 417 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 105 ore. Protocoalele de securitate au fost revizuite de 145 ori anul acesta. Ultimul incident a avut loc cu 21 luni in urma. Am efectuat 78 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 273.', 'doc_existing_c4_4.txt', 889, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (2942, 4, 'cave', 1253, 1775839974);
