INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1254, 'Document PeÈ™tera AscendentÄƒ din Guguiova #5', 'Proces verbal intalnire club - sedinta nr. 358. Au participat 113 membri. Am discutat 481 puncte pe ordinea de zi. S-a aprobat bugetul de 488 lei pentru trimestrul urmator. Am planificat 126 expeditii in urmatoarele luni. S-au inscris 104 membri noi. Am evaluat 225 rapoarte de explorare. S-a votat achizitionarea de echipament in valoare de 396 lei. Urmatoarea sedinta: peste 348 saptamani. Am desemnat 97 responsabili pentru proiecte.', 'doc_existing_c4_5.txt', 436, NULL, 'text_document', 1775839974);
