INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1255, 'Document PeÈ™tera AscendentÄƒ din Guguiova #6', 'Studiu speleogenetic - sectorul 305. Am analizat 61 probe de calcar sub microscop. Varsta estimata a galeriei: 297 milioane de ani. Am identificat 473 faze de speleogeneza. Nivelul freatic actual este la 283 metri adancime. Am corelat cu 187 alte pesteri din zona. Porozitatea medie a rocii: 496 procente. Am realizat 290 sectiuni subtiri din probe. Studiul va fi publicat in volumul 409 al buletinului. Am colaborat cu 401 geologi specialisti.', 'doc_existing_c4_6.txt', 444, NULL, 'text_document', 1775839974);
