INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1260, 'Document PeÈ™tera AscendentÄƒ din Guguiova #11', 'Evaluare risc - sectorul 109. Am identificat 33 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 101 centimetri. Nivelul apei poate creste cu 474 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 364 metri. Am instalat 225 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 268 minute. Echipamentul de prim ajutor este pozitionat la statia 407. Am testat comunicarea radio in 192 puncte critice. Semnalul radio este pierdut dupa 409 metri de la intrare. Am recomandat echipa minima de 153 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 270 ore. Protocoalele de securitate au fost revizuite de 182 ori anul acesta. Ultimul incident a avut loc cu 9 luni in urma. Am efectuat 462 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 24.', 'doc_existing_c4_11.txt', 887, NULL, 'text_document', 1775839974);
