INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1261, 'Document PeÈ™tera AscendentÄƒ din Guguiova #12', 'Raport geologic - profil 433. Stratele de calcar apartin etajului 13. Grosimea medie a stratelor este de 198 centimetri. Fisurile tectonice au un azimut predominant de 380 grade. Am recoltat 8 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 397 procente. Concretii de aragonita au fost gasite la cota 117. Varsta estimata a speleothemelor: 259 mii de ani. Depozitele clastice au o grosime de 268 centimetri. Am identificat 11 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 11 metri. Analiza XRD confirma 180 faze minerale distincte. Sectorul analizat are o lungime de 113 metri. Am realizat 204 profile transversale ale galeriei. Cutele vizibile au amplitudini de 438 centimetri.', 'doc_existing_c4_12.txt', 725, NULL, 'text_document', 1775839974);
