INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1263, 'Document PeÈ™tera AscendentÄƒ din Guguiova #14', 'Fisa tehnica echipare put - verticala nr. 168. Adancimea: 225 metri. Am instalat 457 spituri din otel inoxidabil. Distanta intre spituri: 32 metri. Lungimea corzii principale: 48 metri. Coarda de siguranta: 353 metri. Am montat 453 protectoare de franghie. Fractionarea se face la 21 metri de buza putului. Deviatia este la 112 metri sub fractionare. Am testat echiparea cu 130 coborari. Ultimul control al spiturilor: acum 183 luni.', 'doc_existing_c4_14.txt', 433, NULL, 'text_document', 1775839974);
