INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1275, 'Document PeÈ™tera cu SÄƒritoare din Guguiova #2', 'Evidenta resurse hidrologice - punctul 388. Debitul mediu masurat: 32 litri pe secunda. Am efectuat 178 masuratori in perioade diferite. Temperatura apei: 418 grade Celsius, constanta. pH-ul masurat: 340 unitati. Conductivitatea electrica: 484 microsiemensi. Am injectat 270 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 315 ore. Distanta estimata: 382 metri de conducte carstice. Nivelul maxim in sezonul ploios: 346 centimetri peste normal. Am monitorizat 414 izvoare din bazin. Volumul estimat al lacului subteran: 171 metri cubi.', 'doc_existing_c5_2.txt', 548, NULL, 'text_document', 1775839974);
