INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1277, 'Document PeÈ™tera cu SÄƒritoare din Guguiova #4', 'Studiu speleogenetic - sectorul 431. Am analizat 131 probe de calcar sub microscop. Varsta estimata a galeriei: 297 milioane de ani. Am identificat 486 faze de speleogeneza. Nivelul freatic actual este la 356 metri adancime. Am corelat cu 149 alte pesteri din zona. Porozitatea medie a rocii: 330 procente. Am realizat 3 sectiuni subtiri din probe. Studiul va fi publicat in volumul 353 al buletinului. Am colaborat cu 426 geologi specialisti.', 'doc_existing_c5_4.txt', 443, NULL, 'text_document', 1775839974);
