INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1279, 'Document PeÈ™tera cu SÄƒritoare din Guguiova #6', 'Raport geologic - profil 118. Stratele de calcar apartin etajului 466. Grosimea medie a stratelor este de 90 centimetri. Fisurile tectonice au un azimut predominant de 243 grade. Am recoltat 216 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 314 procente. Concretii de aragonita au fost gasite la cota 394. Varsta estimata a speleothemelor: 248 mii de ani. Depozitele clastice au o grosime de 239 centimetri. Am identificat 259 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 284 metri. Analiza XRD confirma 196 faze minerale distincte. Sectorul analizat are o lungime de 317 metri. Am realizat 226 profile transversale ale galeriei. Cutele vizibile au amplitudini de 491 centimetri.', 'doc_existing_c5_6.txt', 729, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3005, 5, 'cave', 1279, 1775839974);
