INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1280, 'Document PeÈ™tera cu SÄƒritoare din Guguiova #7', 'Evidenta resurse hidrologice - punctul 32. Debitul mediu masurat: 180 litri pe secunda. Am efectuat 272 masuratori in perioade diferite. Temperatura apei: 213 grade Celsius, constanta. pH-ul masurat: 411 unitati. Conductivitatea electrica: 376 microsiemensi. Am injectat 45 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 285 ore. Distanta estimata: 15 metri de conducte carstice. Nivelul maxim in sezonul ploios: 45 centimetri peste normal. Am monitorizat 132 izvoare din bazin. Volumul estimat al lacului subteran: 356 metri cubi.', 'doc_existing_c5_7.txt', 545, NULL, 'text_document', 1775839974);
