INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1283, 'Document PeÈ™tera cu SÄƒritoare din Guguiova #10', 'Raport climatologic subteran - statia 369. Senzorul a inregistrat 455 cicluri complete de temperatura. Temperatura medie anuala: 9 grade Celsius. Amplitudinea termica maxima: 59 grade. Umiditatea relativa medie: 124 procente. Concentratia de CO2: 101 ppm. Curentul de aer maxim masurat: 297 metri pe secunda. Directia predominanta a curentului: sector 302. Datalogerul a functionat 17 zile fara intrerupere. Am descarcat 97 megabytes de date brute. Presiunea barometrica la intrare: 176 mbar. Evaporarea masurata: 266 milimetri pe luna. Am comparat datele cu 414 statii meteorologice de suprafata. Raportul complet include 140 grafice si tabele. Monitorizarea continua de 411 luni confirma stabilitatea climatica.', 'doc_existing_c5_10.txt', 713, NULL, 'text_document', 1775839974);
