INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1287, 'Document PeÈ™tera cu SÄƒritoare din Guguiova #14', 'Nota de mentenanta balize - traseul 4. Am verificat 31 balize reflectorizante. Dintre acestea, 474 au fost inlocuite. Am adaugat 487 balize noi in zonele nemarcate. Distanta medie intre balize: 231 metri. Am folosit 265 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 412 metri cu lampa frontala. Am eliminat 319 marcaje vechi si confuze. Traseul total balizat: 387 metri. Urmatoarea verificare: peste 39 luni. Materialul consumat: 262 benzi reflectorizante.', 'doc_existing_c5_14.txt', 481, NULL, 'text_document', 1775839974);
