INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1301, 'Document PeÈ™tera X1 din Piatra Lupului #1', 'Proces verbal intalnire club - sedinta nr. 113. Au participat 178 membri. Am discutat 349 puncte pe ordinea de zi. S-a aprobat bugetul de 21 lei pentru trimestrul urmator. Am planificat 20 expeditii in urmatoarele luni. S-au inscris 392 membri noi. Am evaluat 362 rapoarte de explorare. S-a votat achizitionarea de echipament in valoare de 451 lei. Urmatoarea sedinta: peste 173 saptamani. Am desemnat 354 responsabili pentru proiecte.', 'doc_existing_c6_1.txt', 435, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3059, 6, 'cave', 1301, 1775839974);
