INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1302, 'Document PeÈ™tera X1 din Piatra Lupului #2', 'Raport geologic - profil 427. Stratele de calcar apartin etajului 486. Grosimea medie a stratelor este de 479 centimetri. Fisurile tectonice au un azimut predominant de 464 grade. Am recoltat 325 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 255 procente. Concretii de aragonita au fost gasite la cota 500. Varsta estimata a speleothemelor: 43 mii de ani. Depozitele clastice au o grosime de 154 centimetri. Am identificat 322 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 358 metri. Analiza XRD confirma 134 faze minerale distincte. Sectorul analizat are o lungime de 333 metri. Am realizat 130 profile transversale ale galeriei. Cutele vizibile au amplitudini de 290 centimetri.', 'doc_existing_c6_2.txt', 729, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3062, 6, 'cave', 1302, 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3063, 24, 'cave_area', 1302, 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3064, 134, 'cave_place', 1302, 1775839974);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1303, 'Document PeÈ™tera X1 din Piatra Lupului #3', 'Raport conservare patrimoniu - obiectiv 304. Am evaluat starea a 174 inscriptii istorice. Dintre acestea, 30 necesita interventie urgenta. Am curatat 102 metri patrati de graffiti modern. Am instalat 64 panouri informative la intrare. Bariera de protectie acopera 211 metri liniari. Am documentat 109 urme de vandalism. Raportul a fost transmis autoritatilor locale in 252 exemplare. Am propus clasificarea a 166 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 75 persoane simultan. Am instruit 49 ghizi locali. Costul estimat al lucrarilor: 257 lei. Termenul de finalizare: 164 luni.', 'doc_existing_c6_3.txt', 602, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3065, 6, 'cave', 1303, 1775839974);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1304, 'Document PeÈ™tera X1 din Piatra Lupului #4', 'Nota de mentenanta balize - traseul 132. Am verificat 331 balize reflectorizante. Dintre acestea, 211 au fost inlocuite. Am adaugat 451 balize noi in zonele nemarcate. Distanta medie intre balize: 3 metri. Am folosit 149 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 224 metri cu lampa frontala. Am eliminat 266 marcaje vechi si confuze. Traseul total balizat: 386 metri. Urmatoarea verificare: peste 439 luni. Materialul consumat: 467 benzi reflectorizante.', 'doc_existing_c6_4.txt', 483, NULL, 'text_document', 1775839974);
