INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1313, 'Document PeÈ™tera B1 din Piatra Lupului #1', 'Evaluare risc - sectorul 420. Am identificat 96 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 298 centimetri. Nivelul apei poate creste cu 271 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 457 metri. Am instalat 15 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 484 minute. Echipamentul de prim ajutor este pozitionat la statia 411. Am testat comunicarea radio in 151 puncte critice. Semnalul radio este pierdut dupa 199 metri de la intrare. Am recomandat echipa minima de 144 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 146 ore. Protocoalele de securitate au fost revizuite de 216 ori anul acesta. Ultimul incident a avut loc cu 289 luni in urma. Am efectuat 376 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 424.', 'doc_existing_c7_1.txt', 889, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3087, 7, 'cave', 1313, 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3088, 292, 'cave_place', 1313, 1775839974);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1314, 'Document PeÈ™tera B1 din Piatra Lupului #2', 'Raport geologic - profil 96. Stratele de calcar apartin etajului 430. Grosimea medie a stratelor este de 291 centimetri. Fisurile tectonice au un azimut predominant de 347 grade. Am recoltat 161 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 239 procente. Concretii de aragonita au fost gasite la cota 155. Varsta estimata a speleothemelor: 342 mii de ani. Depozitele clastice au o grosime de 264 centimetri. Am identificat 252 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 311 metri. Analiza XRD confirma 7 faze minerale distincte. Sectorul analizat are o lungime de 412 metri. Am realizat 428 profile transversale ale galeriei. Cutele vizibile au amplitudini de 272 centimetri.', 'doc_existing_c7_2.txt', 727, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3089, 7, 'cave', 1314, 1775839974);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1315, 'Document PeÈ™tera B1 din Piatra Lupului #3', 'Studiu speleogenetic - sectorul 186. Am analizat 388 probe de calcar sub microscop. Varsta estimata a galeriei: 201 milioane de ani. Am identificat 289 faze de speleogeneza. Nivelul freatic actual este la 385 metri adancime. Am corelat cu 366 alte pesteri din zona. Porozitatea medie a rocii: 263 procente. Am realizat 499 sectiuni subtiri din probe. Studiul va fi publicat in volumul 148 al buletinului. Am colaborat cu 53 geologi specialisti.', 'doc_existing_c7_3.txt', 444, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3090, 7, 'cave', 1315, 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3091, 265, 'cave_place', 1315, 1775839974);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1316, 'Document PeÈ™tera B1 din Piatra Lupului #4', 'Raport climatologic subteran - statia 2. Senzorul a inregistrat 366 cicluri complete de temperatura. Temperatura medie anuala: 338 grade Celsius. Amplitudinea termica maxima: 124 grade. Umiditatea relativa medie: 148 procente. Concentratia de CO2: 292 ppm. Curentul de aer maxim masurat: 112 metri pe secunda. Directia predominanta a curentului: sector 10. Datalogerul a functionat 257 zile fara intrerupere. Am descarcat 278 megabytes de date brute. Presiunea barometrica la intrare: 451 mbar. Evaporarea masurata: 125 milimetri pe luna. Am comparat datele cu 48 statii meteorologice de suprafata. Raportul complet include 66 grafice si tabele. Monitorizarea continua de 52 luni confirma stabilitatea climatica.', 'doc_existing_c7_4.txt', 712, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3092, 7, 'cave', 1316, 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3093, 27, 'cave_area', 1316, 1775839974);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1317, 'Document PeÈ™tera B1 din Piatra Lupului #5', 'Fisa tehnica echipare put - verticala nr. 21. Adancimea: 230 metri. Am instalat 261 spituri din otel inoxidabil. Distanta intre spituri: 331 metri. Lungimea corzii principale: 23 metri. Coarda de siguranta: 323 metri. Am montat 25 protectoare de franghie. Fractionarea se face la 364 metri de buza putului. Deviatia este la 462 metri sub fractionare. Am testat echiparea cu 313 coborari. Ultimul control al spiturilor: acum 104 luni.', 'doc_existing_c7_5.txt', 433, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3094, 7, 'cave', 1317, 1775839974);
