INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1322, 'Document PeÈ™tera B1 din Piatra Lupului #10', 'Evaluare risc - sectorul 62. Am identificat 303 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 307 centimetri. Nivelul apei poate creste cu 441 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 344 metri. Am instalat 21 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 77 minute. Echipamentul de prim ajutor este pozitionat la statia 361. Am testat comunicarea radio in 151 puncte critice. Semnalul radio este pierdut dupa 320 metri de la intrare. Am recomandat echipa minima de 159 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 177 ore. Protocoalele de securitate au fost revizuite de 198 ori anul acesta. Ultimul incident a avut loc cu 444 luni in urma. Am efectuat 308 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 98.', 'doc_existing_c7_10.txt', 887, NULL, 'text_document', 1775839974);
