INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1323, 'Document PeÈ™tera B1 din Piatra Lupului #11', 'Raport conservare patrimoniu - obiectiv 204. Am evaluat starea a 243 inscriptii istorice. Dintre acestea, 493 necesita interventie urgenta. Am curatat 248 metri patrati de graffiti modern. Am instalat 80 panouri informative la intrare. Bariera de protectie acopera 411 metri liniari. Am documentat 13 urme de vandalism. Raportul a fost transmis autoritatilor locale in 443 exemplare. Am propus clasificarea a 138 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 213 persoane simultan. Am instruit 85 ghizi locali. Costul estimat al lucrarilor: 346 lei. Termenul de finalizare: 79 luni.', 'doc_existing_c7_11.txt', 602, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3109, 7, 'cave', 1323, 1775839974);
