INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1324, 'Document PeÈ™tera B1 din Piatra Lupului #12', 'Evaluare risc - sectorul 77. Am identificat 86 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 149 centimetri. Nivelul apei poate creste cu 338 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 49 metri. Am instalat 488 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 166 minute. Echipamentul de prim ajutor este pozitionat la statia 315. Am testat comunicarea radio in 241 puncte critice. Semnalul radio este pierdut dupa 220 metri de la intrare. Am recomandat echipa minima de 376 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 184 ore. Protocoalele de securitate au fost revizuite de 289 ori anul acesta. Ultimul incident a avut loc cu 35 luni in urma. Am efectuat 277 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 57.', 'doc_existing_c7_12.txt', 886, NULL, 'text_document', 1775839974);
