INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1325, 'Document PeÈ™tera B1 din Piatra Lupului #13', 'Raport conservare patrimoniu - obiectiv 394. Am evaluat starea a 363 inscriptii istorice. Dintre acestea, 53 necesita interventie urgenta. Am curatat 336 metri patrati de graffiti modern. Am instalat 499 panouri informative la intrare. Bariera de protectie acopera 144 metri liniari. Am documentat 205 urme de vandalism. Raportul a fost transmis autoritatilor locale in 94 exemplare. Am propus clasificarea a 154 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 107 persoane simultan. Am instruit 214 ghizi locali. Costul estimat al lucrarilor: 53 lei. Termenul de finalizare: 346 luni.', 'doc_existing_c7_13.txt', 603, NULL, 'text_document', 1775839974);
