INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1326, 'Document PeÈ™tera B1 din Piatra Lupului #14', 'Raport geologic - profil 65. Stratele de calcar apartin etajului 165. Grosimea medie a stratelor este de 480 centimetri. Fisurile tectonice au un azimut predominant de 307 grade. Am recoltat 407 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 152 procente. Concretii de aragonita au fost gasite la cota 59. Varsta estimata a speleothemelor: 211 mii de ani. Depozitele clastice au o grosime de 249 centimetri. Am identificat 109 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 276 metri. Analiza XRD confirma 64 faze minerale distincte. Sectorul analizat are o lungime de 215 metri. Am realizat 6 profile transversale ale galeriei. Cutele vizibile au amplitudini de 266 centimetri.', 'doc_existing_c7_14.txt', 725, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3116, 7, 'cave', 1326, 1775839974);
