INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1327, 'Document PeÈ™tera B1 din Piatra Lupului #15', 'Raport geologic - profil 260. Stratele de calcar apartin etajului 242. Grosimea medie a stratelor este de 421 centimetri. Fisurile tectonice au un azimut predominant de 53 grade. Am recoltat 461 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 211 procente. Concretii de aragonita au fost gasite la cota 345. Varsta estimata a speleothemelor: 308 mii de ani. Depozitele clastice au o grosime de 285 centimetri. Am identificat 67 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 300 metri. Analiza XRD confirma 362 faze minerale distincte. Sectorul analizat are o lungime de 125 metri. Am realizat 237 profile transversale ale galeriei. Cutele vizibile au amplitudini de 143 centimetri.', 'doc_existing_c7_15.txt', 728, NULL, 'text_document', 1775839974);
