INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1328, 'Document PeÈ™tera B1 din Piatra Lupului #16', 'Raport conservare patrimoniu - obiectiv 258. Am evaluat starea a 53 inscriptii istorice. Dintre acestea, 294 necesita interventie urgenta. Am curatat 10 metri patrati de graffiti modern. Am instalat 27 panouri informative la intrare. Bariera de protectie acopera 342 metri liniari. Am documentat 413 urme de vandalism. Raportul a fost transmis autoritatilor locale in 74 exemplare. Am propus clasificarea a 118 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 285 persoane simultan. Am instruit 61 ghizi locali. Costul estimat al lucrarilor: 394 lei. Termenul de finalizare: 425 luni.', 'doc_existing_c7_16.txt', 601, NULL, 'text_document', 1775839974);
