INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1329, 'Document PeÈ™tera B1 din Piatra Lupului #17', 'Studiu speleogenetic - sectorul 72. Am analizat 449 probe de calcar sub microscop. Varsta estimata a galeriei: 491 milioane de ani. Am identificat 248 faze de speleogeneza. Nivelul freatic actual este la 154 metri adancime. Am corelat cu 172 alte pesteri din zona. Porozitatea medie a rocii: 52 procente. Am realizat 411 sectiuni subtiri din probe. Studiul va fi publicat in volumul 118 al buletinului. Am colaborat cu 397 geologi specialisti.', 'doc_existing_c7_17.txt', 443, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3123, 7, 'cave', 1329, 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3124, 333, 'cave_place', 1329, 1775839974);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1330, 'Document PeÈ™tera B1 din Piatra Lupului #18', 'Proces verbal intalnire club - sedinta nr. 427. Au participat 36 membri. Am discutat 93 puncte pe ordinea de zi. S-a aprobat bugetul de 6 lei pentru trimestrul urmator. Am planificat 288 expeditii in urmatoarele luni. S-au inscris 329 membri noi. Am evaluat 423 rapoarte de explorare. S-a votat achizitionarea de echipament in valoare de 13 lei. Urmatoarea sedinta: peste 173 saptamani. Am desemnat 33 responsabili pentru proiecte.', 'doc_existing_c7_18.txt', 431, NULL, 'text_document', 1775839974);
