INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1349, 'Document PeÈ™tera B2 din Piatra Lupului #1', 'Studiu speleogenetic - sectorul 197. Am analizat 118 probe de calcar sub microscop. Varsta estimata a galeriei: 455 milioane de ani. Am identificat 206 faze de speleogeneza. Nivelul freatic actual este la 256 metri adancime. Am corelat cu 14 alte pesteri din zona. Porozitatea medie a rocii: 142 procente. Am realizat 124 sectiuni subtiri din probe. Studiul va fi publicat in volumul 333 al buletinului. Am colaborat cu 156 geologi specialisti.', 'doc_existing_c8_1.txt', 444, NULL, 'text_document', 1775839974);
