INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1350, 'Document PeÈ™tera B2 din Piatra Lupului #2', 'Evidenta resurse hidrologice - punctul 205. Debitul mediu masurat: 214 litri pe secunda. Am efectuat 387 masuratori in perioade diferite. Temperatura apei: 323 grade Celsius, constanta. pH-ul masurat: 307 unitati. Conductivitatea electrica: 314 microsiemensi. Am injectat 56 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 184 ore. Distanta estimata: 25 metri de conducte carstice. Nivelul maxim in sezonul ploios: 418 centimetri peste normal. Am monitorizat 25 izvoare din bazin. Volumul estimat al lacului subteran: 105 metri cubi.', 'doc_existing_c8_2.txt', 546, NULL, 'text_document', 1775839974);
