INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1353, 'Document PeÈ™tera B2 din Piatra Lupului #5', 'Nota de mentenanta balize - traseul 178. Am verificat 285 balize reflectorizante. Dintre acestea, 282 au fost inlocuite. Am adaugat 259 balize noi in zonele nemarcate. Distanta medie intre balize: 354 metri. Am folosit 450 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 120 metri cu lampa frontala. Am eliminat 4 marcaje vechi si confuze. Traseul total balizat: 378 metri. Urmatoarea verificare: peste 400 luni. Materialul consumat: 439 benzi reflectorizante.', 'doc_existing_c8_5.txt', 483, NULL, 'text_document', 1775839974);
