INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1356, 'Document PeÈ™tera B2 din Piatra Lupului #8', 'Evaluare risc - sectorul 55. Am identificat 258 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 422 centimetri. Nivelul apei poate creste cu 166 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 69 metri. Am instalat 292 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 182 minute. Echipamentul de prim ajutor este pozitionat la statia 228. Am testat comunicarea radio in 313 puncte critice. Semnalul radio este pierdut dupa 91 metri de la intrare. Am recomandat echipa minima de 179 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 72 ore. Protocoalele de securitate au fost revizuite de 472 ori anul acesta. Ultimul incident a avut loc cu 445 luni in urma. Am efectuat 427 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 192.', 'doc_existing_c8_8.txt', 887, NULL, 'text_document', 1775839974);
