INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1365, 'Document PeÈ™tera B3 din Piatra Lupului #1', 'Raport conservare patrimoniu - obiectiv 58. Am evaluat starea a 451 inscriptii istorice. Dintre acestea, 64 necesita interventie urgenta. Am curatat 38 metri patrati de graffiti modern. Am instalat 38 panouri informative la intrare. Bariera de protectie acopera 489 metri liniari. Am documentat 419 urme de vandalism. Raportul a fost transmis autoritatilor locale in 237 exemplare. Am propus clasificarea a 438 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 331 persoane simultan. Am instruit 328 ghizi locali. Costul estimat al lucrarilor: 201 lei. Termenul de finalizare: 197 luni.', 'doc_existing_c9_1.txt', 602, NULL, 'text_document', 1775839974);
