INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1367, 'Document PeÈ™tera B3 din Piatra Lupului #3', 'Raport geologic - profil 275. Stratele de calcar apartin etajului 276. Grosimea medie a stratelor este de 335 centimetri. Fisurile tectonice au un azimut predominant de 345 grade. Am recoltat 111 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 190 procente. Concretii de aragonita au fost gasite la cota 421. Varsta estimata a speleothemelor: 36 mii de ani. Depozitele clastice au o grosime de 304 centimetri. Am identificat 293 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 452 metri. Analiza XRD confirma 248 faze minerale distincte. Sectorul analizat are o lungime de 459 metri. Am realizat 148 profile transversale ale galeriei. Cutele vizibile au amplitudini de 59 centimetri.', 'doc_existing_c9_3.txt', 728, NULL, 'text_document', 1775839974);
