INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1370, 'Document PeÈ™tera B3 din Piatra Lupului #6', 'Fisa tehnica echipare put - verticala nr. 186. Adancimea: 136 metri. Am instalat 2 spituri din otel inoxidabil. Distanta intre spituri: 284 metri. Lungimea corzii principale: 203 metri. Coarda de siguranta: 220 metri. Am montat 420 protectoare de franghie. Fractionarea se face la 228 metri de buza putului. Deviatia este la 452 metri sub fractionare. Am testat echiparea cu 430 coborari. Ultimul control al spiturilor: acum 294 luni.', 'doc_existing_c9_6.txt', 434, NULL, 'text_document', 1775839974);
