INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1371, 'Document PeÈ™tera B3 din Piatra Lupului #7', 'Studiu speleogenetic - sectorul 379. Am analizat 341 probe de calcar sub microscop. Varsta estimata a galeriei: 56 milioane de ani. Am identificat 242 faze de speleogeneza. Nivelul freatic actual este la 223 metri adancime. Am corelat cu 141 alte pesteri din zona. Porozitatea medie a rocii: 215 procente. Am realizat 115 sectiuni subtiri din probe. Studiul va fi publicat in volumul 298 al buletinului. Am colaborat cu 25 geologi specialisti.', 'doc_existing_c9_7.txt', 443, NULL, 'text_document', 1775839974);
