INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1372, 'Document PeÈ™tera B3 din Piatra Lupului #8', 'Nota de mentenanta balize - traseul 182. Am verificat 326 balize reflectorizante. Dintre acestea, 203 au fost inlocuite. Am adaugat 403 balize noi in zonele nemarcate. Distanta medie intre balize: 69 metri. Am folosit 74 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 298 metri cu lampa frontala. Am eliminat 304 marcaje vechi si confuze. Traseul total balizat: 450 metri. Urmatoarea verificare: peste 189 luni. Materialul consumat: 30 benzi reflectorizante.', 'doc_existing_c9_8.txt', 482, NULL, 'text_document', 1775839974);
