INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1374, 'Document PeÈ™tera B3 din Piatra Lupului #10', 'Fisa tehnica echipare put - verticala nr. 214. Adancimea: 74 metri. Am instalat 243 spituri din otel inoxidabil. Distanta intre spituri: 274 metri. Lungimea corzii principale: 390 metri. Coarda de siguranta: 393 metri. Am montat 185 protectoare de franghie. Fractionarea se face la 4 metri de buza putului. Deviatia este la 325 metri sub fractionare. Am testat echiparea cu 456 coborari. Ultimul control al spiturilor: acum 53 luni.', 'doc_existing_c9_10.txt', 432, NULL, 'text_document', 1775839974);
