INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1388, 'Document PeÈ™tera B4 din Piatra Lupului #1', 'Fisa tehnica echipare put - verticala nr. 281. Adancimea: 303 metri. Am instalat 242 spituri din otel inoxidabil. Distanta intre spituri: 354 metri. Lungimea corzii principale: 212 metri. Coarda de siguranta: 151 metri. Am montat 216 protectoare de franghie. Fractionarea se face la 200 metri de buza putului. Deviatia este la 168 metri sub fractionare. Am testat echiparea cu 42 coborari. Ultimul control al spiturilor: acum 494 luni.', 'doc_existing_c10_1.txt', 435, NULL, 'text_document', 1775839974);
