INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1389, 'Document PeÈ™tera B4 din Piatra Lupului #2', 'Studiu speleogenetic - sectorul 173. Am analizat 118 probe de calcar sub microscop. Varsta estimata a galeriei: 276 milioane de ani. Am identificat 336 faze de speleogeneza. Nivelul freatic actual este la 476 metri adancime. Am corelat cu 35 alte pesteri din zona. Porozitatea medie a rocii: 366 procente. Am realizat 419 sectiuni subtiri din probe. Studiul va fi publicat in volumul 399 al buletinului. Am colaborat cu 336 geologi specialisti.', 'doc_existing_c10_2.txt', 444, NULL, 'text_document', 1775839974);
