INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1390, 'Document PeÈ™tera B4 din Piatra Lupului #3', 'Studiu speleogenetic - sectorul 353. Am analizat 420 probe de calcar sub microscop. Varsta estimata a galeriei: 26 milioane de ani. Am identificat 389 faze de speleogeneza. Nivelul freatic actual este la 145 metri adancime. Am corelat cu 189 alte pesteri din zona. Porozitatea medie a rocii: 295 procente. Am realizat 123 sectiuni subtiri din probe. Studiul va fi publicat in volumul 311 al buletinului. Am colaborat cu 16 geologi specialisti.', 'doc_existing_c10_3.txt', 443, NULL, 'text_document', 1775839974);
