INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1391, 'Document PeÈ™tera B4 din Piatra Lupului #4', 'Raport geologic - profil 2. Stratele de calcar apartin etajului 419. Grosimea medie a stratelor este de 467 centimetri. Fisurile tectonice au un azimut predominant de 75 grade. Am recoltat 75 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 207 procente. Concretii de aragonita au fost gasite la cota 101. Varsta estimata a speleothemelor: 357 mii de ani. Depozitele clastice au o grosime de 126 centimetri. Am identificat 309 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 32 metri. Analiza XRD confirma 253 faze minerale distincte. Sectorul analizat are o lungime de 45 metri. Am realizat 457 profile transversale ale galeriei. Cutele vizibile au amplitudini de 152 centimetri.', 'doc_existing_c10_4.txt', 724, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3260, 10, 'cave', 1391, 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3261, 43, 'cave_area', 1391, 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3262, 454, 'cave_place', 1391, 1775839974);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1392, 'Document PeÈ™tera B4 din Piatra Lupului #5', 'Evaluare risc - sectorul 257. Am identificat 24 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 167 centimetri. Nivelul apei poate creste cu 18 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 200 metri. Am instalat 469 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 205 minute. Echipamentul de prim ajutor este pozitionat la statia 106. Am testat comunicarea radio in 221 puncte critice. Semnalul radio este pierdut dupa 373 metri de la intrare. Am recomandat echipa minima de 470 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 293 ore. Protocoalele de securitate au fost revizuite de 319 ori anul acesta. Ultimul incident a avut loc cu 1 luni in urma. Am efectuat 391 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 372.', 'doc_existing_c10_5.txt', 887, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3263, 10, 'cave', 1392, 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3264, 42, 'cave_area', 1392, 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3265, 471, 'cave_place', 1392, 1775839974);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1393, 'Document PeÈ™tera B4 din Piatra Lupului #6', 'Raport geologic - profil 448. Stratele de calcar apartin etajului 44. Grosimea medie a stratelor este de 314 centimetri. Fisurile tectonice au un azimut predominant de 5 grade. Am recoltat 94 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 99 procente. Concretii de aragonita au fost gasite la cota 372. Varsta estimata a speleothemelor: 398 mii de ani. Depozitele clastice au o grosime de 197 centimetri. Am identificat 272 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 428 metri. Analiza XRD confirma 422 faze minerale distincte. Sectorul analizat are o lungime de 64 metri. Am realizat 224 profile transversale ale galeriei. Cutele vizibile au amplitudini de 59 centimetri.', 'doc_existing_c10_6.txt', 723, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3266, 10, 'cave', 1393, 1775839974);
