INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1394, 'Document PeÈ™tera B4 din Piatra Lupului #7', 'Evidenta resurse hidrologice - punctul 411. Debitul mediu masurat: 327 litri pe secunda. Am efectuat 423 masuratori in perioade diferite. Temperatura apei: 126 grade Celsius, constanta. pH-ul masurat: 363 unitati. Conductivitatea electrica: 479 microsiemensi. Am injectat 309 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 383 ore. Distanta estimata: 44 metri de conducte carstice. Nivelul maxim in sezonul ploios: 486 centimetri peste normal. Am monitorizat 480 izvoare din bazin. Volumul estimat al lacului subteran: 273 metri cubi.', 'doc_existing_c10_7.txt', 548, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3268, 10, 'cave', 1394, 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3269, 43, 'cave_area', 1394, 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3270, 457, 'cave_place', 1394, 1775839974);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1395, 'Document PeÈ™tera B4 din Piatra Lupului #8', 'Raport climatologic subteran - statia 302. Senzorul a inregistrat 83 cicluri complete de temperatura. Temperatura medie anuala: 363 grade Celsius. Amplitudinea termica maxima: 191 grade. Umiditatea relativa medie: 288 procente. Concentratia de CO2: 243 ppm. Curentul de aer maxim masurat: 266 metri pe secunda. Directia predominanta a curentului: sector 189. Datalogerul a functionat 137 zile fara intrerupere. Am descarcat 60 megabytes de date brute. Presiunea barometrica la intrare: 478 mbar. Evaporarea masurata: 393 milimetri pe luna. Am comparat datele cu 360 statii meteorologice de suprafata. Raportul complet include 14 grafice si tabele. Monitorizarea continua de 54 luni confirma stabilitatea climatica.', 'doc_existing_c10_8.txt', 714, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3271, 10, 'cave', 1395, 1775839974);
