INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1396, 'Document PeÈ™tera B4 din Piatra Lupului #9', 'Raport geologic - profil 60. Stratele de calcar apartin etajului 356. Grosimea medie a stratelor este de 67 centimetri. Fisurile tectonice au un azimut predominant de 220 grade. Am recoltat 135 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 247 procente. Concretii de aragonita au fost gasite la cota 211. Varsta estimata a speleothemelor: 130 mii de ani. Depozitele clastice au o grosime de 497 centimetri. Am identificat 356 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 251 metri. Analiza XRD confirma 188 faze minerale distincte. Sectorul analizat are o lungime de 299 metri. Am realizat 364 profile transversale ale galeriei. Cutele vizibile au amplitudini de 9 centimetri.', 'doc_existing_c10_9.txt', 726, NULL, 'text_document', 1775839974);
