INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1398, 'Document PeÈ™tera B4 din Piatra Lupului #11', 'Evidenta resurse hidrologice - punctul 449. Debitul mediu masurat: 182 litri pe secunda. Am efectuat 72 masuratori in perioade diferite. Temperatura apei: 271 grade Celsius, constanta. pH-ul masurat: 475 unitati. Conductivitatea electrica: 57 microsiemensi. Am injectat 265 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 78 ore. Distanta estimata: 309 metri de conducte carstice. Nivelul maxim in sezonul ploios: 1 centimetri peste normal. Am monitorizat 251 izvoare din bazin. Volumul estimat al lacului subteran: 454 metri cubi.', 'doc_existing_c10_11.txt', 544, NULL, 'text_document', 1775839974);
