INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1399, 'Document PeÈ™tera B4 din Piatra Lupului #12', 'Raport climatologic subteran - statia 419. Senzorul a inregistrat 292 cicluri complete de temperatura. Temperatura medie anuala: 174 grade Celsius. Amplitudinea termica maxima: 400 grade. Umiditatea relativa medie: 356 procente. Concentratia de CO2: 56 ppm. Curentul de aer maxim masurat: 431 metri pe secunda. Directia predominanta a curentului: sector 290. Datalogerul a functionat 261 zile fara intrerupere. Am descarcat 256 megabytes de date brute. Presiunea barometrica la intrare: 92 mbar. Evaporarea masurata: 113 milimetri pe luna. Am comparat datele cu 432 statii meteorologice de suprafata. Raportul complet include 387 grafice si tabele. Monitorizarea continua de 369 luni confirma stabilitatea climatica.', 'doc_existing_c10_12.txt', 716, NULL, 'text_document', 1775839974);
