INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1411, 'Document PeÈ™tera B5 din Piatra Lupului #1', 'Raport geologic - profil 23. Stratele de calcar apartin etajului 444. Grosimea medie a stratelor este de 271 centimetri. Fisurile tectonice au un azimut predominant de 105 grade. Am recoltat 230 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 228 procente. Concretii de aragonita au fost gasite la cota 145. Varsta estimata a speleothemelor: 325 mii de ani. Depozitele clastice au o grosime de 387 centimetri. Am identificat 178 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 98 metri. Analiza XRD confirma 19 faze minerale distincte. Sectorul analizat are o lungime de 440 metri. Am realizat 91 profile transversale ale galeriei. Cutele vizibile au amplitudini de 37 centimetri.', 'doc_existing_c11_1.txt', 725, NULL, 'text_document', 1775839974);
