INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1412, 'Document PeÈ™tera B5 din Piatra Lupului #2', 'Nota de mentenanta balize - traseul 219. Am verificat 384 balize reflectorizante. Dintre acestea, 397 au fost inlocuite. Am adaugat 69 balize noi in zonele nemarcate. Distanta medie intre balize: 9 metri. Am folosit 197 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 344 metri cu lampa frontala. Am eliminat 292 marcaje vechi si confuze. Traseul total balizat: 215 metri. Urmatoarea verificare: peste 470 luni. Materialul consumat: 246 benzi reflectorizante.', 'doc_existing_c11_2.txt', 482, NULL, 'text_document', 1775839974);
