INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1413, 'Document PeÈ™tera B5 din Piatra Lupului #3', 'Studiu speleogenetic - sectorul 91. Am analizat 1 probe de calcar sub microscop. Varsta estimata a galeriei: 475 milioane de ani. Am identificat 488 faze de speleogeneza. Nivelul freatic actual este la 287 metri adancime. Am corelat cu 374 alte pesteri din zona. Porozitatea medie a rocii: 65 procente. Am realizat 464 sectiuni subtiri din probe. Studiul va fi publicat in volumul 79 al buletinului. Am colaborat cu 406 geologi specialisti.', 'doc_existing_c11_3.txt', 440, NULL, 'text_document', 1775839974);
