INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1415, 'Document PeÈ™tera B5 din Piatra Lupului #5', 'Proces verbal intalnire club - sedinta nr. 422. Au participat 339 membri. Am discutat 71 puncte pe ordinea de zi. S-a aprobat bugetul de 117 lei pentru trimestrul urmator. Am planificat 310 expeditii in urmatoarele luni. S-au inscris 54 membri noi. Am evaluat 448 rapoarte de explorare. S-a votat achizitionarea de echipament in valoare de 300 lei. Urmatoarea sedinta: peste 66 saptamani. Am desemnat 116 responsabili pentru proiecte.', 'doc_existing_c11_5.txt', 434, NULL, 'text_document', 1775839974);
