INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1418, 'Document PeÈ™tera B5 din Piatra Lupului #8', 'Fisa tehnica echipare put - verticala nr. 436. Adancimea: 417 metri. Am instalat 191 spituri din otel inoxidabil. Distanta intre spituri: 267 metri. Lungimea corzii principale: 24 metri. Coarda de siguranta: 29 metri. Am montat 219 protectoare de franghie. Fractionarea se face la 244 metri de buza putului. Deviatia este la 444 metri sub fractionare. Am testat echiparea cu 84 coborari. Ultimul control al spiturilor: acum 207 luni.', 'doc_existing_c11_8.txt', 433, NULL, 'text_document', 1775839974);
