INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1420, 'Document PeÈ™tera B5 din Piatra Lupului #10', 'Fisa tehnica echipare put - verticala nr. 282. Adancimea: 355 metri. Am instalat 478 spituri din otel inoxidabil. Distanta intre spituri: 158 metri. Lungimea corzii principale: 290 metri. Coarda de siguranta: 296 metri. Am montat 322 protectoare de franghie. Fractionarea se face la 4 metri de buza putului. Deviatia este la 244 metri sub fractionare. Am testat echiparea cu 254 coborari. Ultimul control al spiturilor: acum 29 luni.', 'doc_existing_c11_10.txt', 433, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3332, 11, 'cave', 1420, 1775839974);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1421, 'Document PeÈ™tera B5 din Piatra Lupului #11', 'Nota de mentenanta balize - traseul 311. Am verificat 418 balize reflectorizante. Dintre acestea, 53 au fost inlocuite. Am adaugat 23 balize noi in zonele nemarcate. Distanta medie intre balize: 468 metri. Am folosit 379 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 470 metri cu lampa frontala. Am eliminat 42 marcaje vechi si confuze. Traseul total balizat: 431 metri. Urmatoarea verificare: peste 257 luni. Materialul consumat: 228 benzi reflectorizante.', 'doc_existing_c11_11.txt', 482, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3333, 11, 'cave', 1421, 1775839974);
