INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1422, 'Document PeÈ™tera B5 din Piatra Lupului #12', 'Studiu speleogenetic - sectorul 275. Am analizat 276 probe de calcar sub microscop. Varsta estimata a galeriei: 485 milioane de ani. Am identificat 164 faze de speleogeneza. Nivelul freatic actual este la 300 metri adancime. Am corelat cu 4 alte pesteri din zona. Porozitatea medie a rocii: 432 procente. Am realizat 291 sectiuni subtiri din probe. Studiul va fi publicat in volumul 6 al buletinului. Am colaborat cu 223 geologi specialisti.', 'doc_existing_c11_12.txt', 441, NULL, 'text_document', 1775839974);
