INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1430, 'Document PeÈ™tera C1 din Piatra Lupului #1', 'Evidenta resurse hidrologice - punctul 299. Debitul mediu masurat: 137 litri pe secunda. Am efectuat 96 masuratori in perioade diferite. Temperatura apei: 305 grade Celsius, constanta. pH-ul masurat: 368 unitati. Conductivitatea electrica: 26 microsiemensi. Am injectat 78 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 260 ore. Distanta estimata: 1 metri de conducte carstice. Nivelul maxim in sezonul ploios: 359 centimetri peste normal. Am monitorizat 328 izvoare din bazin. Volumul estimat al lacului subteran: 321 metri cubi.', 'doc_existing_c12_1.txt', 544, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3351, 12, 'cave', 1430, 1775839974);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1431, 'Document PeÈ™tera C1 din Piatra Lupului #2', 'Nota de mentenanta balize - traseul 450. Am verificat 377 balize reflectorizante. Dintre acestea, 429 au fost inlocuite. Am adaugat 379 balize noi in zonele nemarcate. Distanta medie intre balize: 387 metri. Am folosit 277 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 357 metri cu lampa frontala. Am eliminat 335 marcaje vechi si confuze. Traseul total balizat: 493 metri. Urmatoarea verificare: peste 263 luni. Materialul consumat: 197 benzi reflectorizante.', 'doc_existing_c12_2.txt', 485, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3352, 12, 'cave', 1431, 1775839974);
