INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1432, 'Document PeÈ™tera C1 din Piatra Lupului #3', 'Fisa tehnica echipare put - verticala nr. 281. Adancimea: 15 metri. Am instalat 220 spituri din otel inoxidabil. Distanta intre spituri: 282 metri. Lungimea corzii principale: 159 metri. Coarda de siguranta: 26 metri. Am montat 496 protectoare de franghie. Fractionarea se face la 267 metri de buza putului. Deviatia este la 7 metri sub fractionare. Am testat echiparea cu 134 coborari. Ultimul control al spiturilor: acum 455 luni.', 'doc_existing_c12_3.txt', 432, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3354, 12, 'cave', 1432, 1775839974);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1433, 'Document PeÈ™tera C1 din Piatra Lupului #4', 'Evaluare risc - sectorul 137. Am identificat 434 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 315 centimetri. Nivelul apei poate creste cu 31 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 299 metri. Am instalat 173 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 156 minute. Echipamentul de prim ajutor este pozitionat la statia 436. Am testat comunicarea radio in 298 puncte critice. Semnalul radio este pierdut dupa 467 metri de la intrare. Am recomandat echipa minima de 368 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 282 ore. Protocoalele de securitate au fost revizuite de 301 ori anul acesta. Ultimul incident a avut loc cu 30 luni in urma. Am efectuat 417 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 287.', 'doc_existing_c12_4.txt', 889, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3355, 12, 'cave', 1433, 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3356, 54, 'cave_area', 1433, 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3357, 580, 'cave_place', 1433, 1775839974);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1434, 'Document PeÈ™tera C1 din Piatra Lupului #5', 'Raport climatologic subteran - statia 373. Senzorul a inregistrat 273 cicluri complete de temperatura. Temperatura medie anuala: 294 grade Celsius. Amplitudinea termica maxima: 290 grade. Umiditatea relativa medie: 407 procente. Concentratia de CO2: 84 ppm. Curentul de aer maxim masurat: 314 metri pe secunda. Directia predominanta a curentului: sector 276. Datalogerul a functionat 66 zile fara intrerupere. Am descarcat 72 megabytes de date brute. Presiunea barometrica la intrare: 74 mbar. Evaporarea masurata: 474 milimetri pe luna. Am comparat datele cu 319 statii meteorologice de suprafata. Raportul complet include 136 grafice si tabele. Monitorizarea continua de 326 luni confirma stabilitatea climatica.', 'doc_existing_c12_5.txt', 714, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3358, 12, 'cave', 1434, 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3359, 53, 'cave_area', 1434, 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3360, 552, 'cave_place', 1434, 1775839974);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1435, 'Document PeÈ™tera C1 din Piatra Lupului #6', 'Evaluare risc - sectorul 243. Am identificat 449 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 9 centimetri. Nivelul apei poate creste cu 61 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 40 metri. Am instalat 495 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 4 minute. Echipamentul de prim ajutor este pozitionat la statia 22. Am testat comunicarea radio in 228 puncte critice. Semnalul radio este pierdut dupa 493 metri de la intrare. Am recomandat echipa minima de 413 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 354 ore. Protocoalele de securitate au fost revizuite de 459 ori anul acesta. Ultimul incident a avut loc cu 33 luni in urma. Am efectuat 176 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 305.', 'doc_existing_c12_6.txt', 883, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3361, 12, 'cave', 1435, 1775839974);
