INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1453, 'Document PeÈ™tera C2 din Piatra Lupului #1', 'Nota de mentenanta balize - traseul 427. Am verificat 133 balize reflectorizante. Dintre acestea, 441 au fost inlocuite. Am adaugat 487 balize noi in zonele nemarcate. Distanta medie intre balize: 433 metri. Am folosit 382 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 354 metri cu lampa frontala. Am eliminat 316 marcaje vechi si confuze. Traseul total balizat: 495 metri. Urmatoarea verificare: peste 457 luni. Materialul consumat: 364 benzi reflectorizante.', 'doc_existing_c13_1.txt', 485, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3408, 13, 'cave', 1453, 1775839974);
