INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1454, 'Document PeÈ™tera C2 din Piatra Lupului #2', 'Evaluare risc - sectorul 99. Am identificat 245 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 274 centimetri. Nivelul apei poate creste cu 206 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 266 metri. Am instalat 138 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 51 minute. Echipamentul de prim ajutor este pozitionat la statia 143. Am testat comunicarea radio in 98 puncte critice. Semnalul radio este pierdut dupa 421 metri de la intrare. Am recomandat echipa minima de 192 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 420 ore. Protocoalele de securitate au fost revizuite de 376 ori anul acesta. Ultimul incident a avut loc cu 199 luni in urma. Am efectuat 404 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 408.', 'doc_existing_c13_2.txt', 888, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3411, 13, 'cave', 1454, 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3412, 56, 'cave_area', 1454, 1775839974);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1455, 'Document PeÈ™tera C2 din Piatra Lupului #3', 'Studiu speleogenetic - sectorul 484. Am analizat 106 probe de calcar sub microscop. Varsta estimata a galeriei: 449 milioane de ani. Am identificat 84 faze de speleogeneza. Nivelul freatic actual este la 444 metri adancime. Am corelat cu 191 alte pesteri din zona. Porozitatea medie a rocii: 270 procente. Am realizat 352 sectiuni subtiri din probe. Studiul va fi publicat in volumul 242 al buletinului. Am colaborat cu 202 geologi specialisti.', 'doc_existing_c13_3.txt', 444, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3413, 13, 'cave', 1455, 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3414, 633, 'cave_place', 1455, 1775839974);
