INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1462, 'Document PeÈ™tera C3 din Piatra Lupului #1', 'Raport geologic - profil 317. Stratele de calcar apartin etajului 19. Grosimea medie a stratelor este de 152 centimetri. Fisurile tectonice au un azimut predominant de 111 grade. Am recoltat 166 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 303 procente. Concretii de aragonita au fost gasite la cota 18. Varsta estimata a speleothemelor: 427 mii de ani. Depozitele clastice au o grosime de 440 centimetri. Am identificat 325 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 140 metri. Analiza XRD confirma 314 faze minerale distincte. Sectorul analizat are o lungime de 197 metri. Am realizat 248 profile transversale ale galeriei. Cutele vizibile au amplitudini de 274 centimetri.', 'doc_existing_c14_1.txt', 728, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3429, 14, 'cave', 1462, 1775839974);
