INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1487, 'Document PeÈ™tera C5 din Piatra Lupului #3', 'Nota de mentenanta balize - traseul 231. Am verificat 99 balize reflectorizante. Dintre acestea, 421 au fost inlocuite. Am adaugat 370 balize noi in zonele nemarcate. Distanta medie intre balize: 350 metri. Am folosit 240 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 389 metri cu lampa frontala. Am eliminat 64 marcaje vechi si confuze. Traseul total balizat: 459 metri. Urmatoarea verificare: peste 206 luni. Materialul consumat: 119 benzi reflectorizante.', 'doc_existing_c16_3.txt', 483, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3480, 16, 'cave', 1487, 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3481, 61, 'cave_area', 1487, 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3482, 813, 'cave_place', 1487, 1775839974);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1488, 'Document PeÈ™tera C5 din Piatra Lupului #4', 'Proces verbal intalnire club - sedinta nr. 43. Au participat 239 membri. Am discutat 121 puncte pe ordinea de zi. S-a aprobat bugetul de 72 lei pentru trimestrul urmator. Am planificat 494 expeditii in urmatoarele luni. S-au inscris 366 membri noi. Am evaluat 460 rapoarte de explorare. S-a votat achizitionarea de echipament in valoare de 342 lei. Urmatoarea sedinta: peste 358 saptamani. Am desemnat 245 responsabili pentru proiecte.', 'doc_existing_c16_4.txt', 435, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3483, 16, 'cave', 1488, 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3484, 809, 'cave_place', 1488, 1775839974);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1489, 'Document PeÈ™tera C5 din Piatra Lupului #5', 'Raport conservare patrimoniu - obiectiv 19. Am evaluat starea a 430 inscriptii istorice. Dintre acestea, 203 necesita interventie urgenta. Am curatat 464 metri patrati de graffiti modern. Am instalat 392 panouri informative la intrare. Bariera de protectie acopera 486 metri liniari. Am documentat 422 urme de vandalism. Raportul a fost transmis autoritatilor locale in 198 exemplare. Am propus clasificarea a 64 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 285 persoane simultan. Am instruit 107 ghizi locali. Costul estimat al lucrarilor: 212 lei. Termenul de finalizare: 76 luni.', 'doc_existing_c16_5.txt', 603, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3485, 16, 'cave', 1489, 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3486, 794, 'cave_place', 1489, 1775839974);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1490, 'Document PeÈ™tera C5 din Piatra Lupului #6', 'Studiu speleogenetic - sectorul 331. Am analizat 152 probe de calcar sub microscop. Varsta estimata a galeriei: 301 milioane de ani. Am identificat 47 faze de speleogeneza. Nivelul freatic actual este la 317 metri adancime. Am corelat cu 329 alte pesteri din zona. Porozitatea medie a rocii: 381 procente. Am realizat 45 sectiuni subtiri din probe. Studiul va fi publicat in volumul 246 al buletinului. Am colaborat cu 264 geologi specialisti.', 'doc_existing_c16_6.txt', 443, NULL, 'text_document', 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3487, 16, 'cave', 1490, 1775839974);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3488, 60, 'cave_area', 1490, 1775839974);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1491, 'Document PeÈ™tera C5 din Piatra Lupului #7', 'Studiu speleogenetic - sectorul 126. Am analizat 493 probe de calcar sub microscop. Varsta estimata a galeriei: 383 milioane de ani. Am identificat 426 faze de speleogeneza. Nivelul freatic actual este la 363 metri adancime. Am corelat cu 129 alte pesteri din zona. Porozitatea medie a rocii: 416 procente. Am realizat 95 sectiuni subtiri din probe. Studiul va fi publicat in volumul 340 al buletinului. Am colaborat cu 20 geologi specialisti.', 'doc_existing_c16_7.txt', 443, NULL, 'text_document', 1775839974);
