INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1540, 'Document PeÈ™tera C8 din Piatra Lupului #7', 'Evaluare risc - sectorul 402. Am identificat 80 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 311 centimetri. Nivelul apei poate creste cu 90 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 366 metri. Am instalat 261 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 177 minute. Echipamentul de prim ajutor este pozitionat la statia 455. Am testat comunicarea radio in 451 puncte critice. Semnalul radio este pierdut dupa 69 metri de la intrare. Am recomandat echipa minima de 226 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 286 ore. Protocoalele de securitate au fost revizuite de 78 ori anul acesta. Ultimul incident a avut loc cu 121 luni in urma. Am efectuat 345 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 129.', 'doc_existing_c19_7.txt', 887, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3601, 19, 'cave', 1540, 1775839975);
