INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1541, 'Document PeÈ™tera C8 din Piatra Lupului #8', 'Evaluare risc - sectorul 315. Am identificat 435 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 2 centimetri. Nivelul apei poate creste cu 335 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 178 metri. Am instalat 48 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 144 minute. Echipamentul de prim ajutor este pozitionat la statia 2. Am testat comunicarea radio in 469 puncte critice. Semnalul radio este pierdut dupa 174 metri de la intrare. Am recomandat echipa minima de 407 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 444 ore. Protocoalele de securitate au fost revizuite de 233 ori anul acesta. Ultimul incident a avut loc cu 118 luni in urma. Am efectuat 241 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 62.', 'doc_existing_c19_8.txt', 885, NULL, 'text_document', 1775839975);
