INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1545, 'Document PeÈ™tera C8 din Piatra Lupului #12', 'Raport conservare patrimoniu - obiectiv 35. Am evaluat starea a 306 inscriptii istorice. Dintre acestea, 178 necesita interventie urgenta. Am curatat 349 metri patrati de graffiti modern. Am instalat 499 panouri informative la intrare. Bariera de protectie acopera 232 metri liniari. Am documentat 28 urme de vandalism. Raportul a fost transmis autoritatilor locale in 424 exemplare. Am propus clasificarea a 16 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 354 persoane simultan. Am instruit 264 ghizi locali. Costul estimat al lucrarilor: 98 lei. Termenul de finalizare: 61 luni.', 'doc_existing_c19_12.txt', 601, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3612, 19, 'cave', 1545, 1775839975);
