INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1560, 'Document PeÈ™tera C9 din Piatra Lupului #4', 'Raport climatologic subteran - statia 275. Senzorul a inregistrat 422 cicluri complete de temperatura. Temperatura medie anuala: 165 grade Celsius. Amplitudinea termica maxima: 446 grade. Umiditatea relativa medie: 285 procente. Concentratia de CO2: 17 ppm. Curentul de aer maxim masurat: 402 metri pe secunda. Directia predominanta a curentului: sector 122. Datalogerul a functionat 356 zile fara intrerupere. Am descarcat 456 megabytes de date brute. Presiunea barometrica la intrare: 112 mbar. Evaporarea masurata: 126 milimetri pe luna. Am comparat datele cu 57 statii meteorologice de suprafata. Raportul complet include 323 grafice si tabele. Monitorizarea continua de 250 luni confirma stabilitatea climatica.', 'doc_existing_c20_4.txt', 716, NULL, 'text_document', 1775839975);
