INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1564, 'Document PeÈ™tera C9 din Piatra Lupului #8', 'Raport geologic - profil 388. Stratele de calcar apartin etajului 22. Grosimea medie a stratelor este de 72 centimetri. Fisurile tectonice au un azimut predominant de 277 grade. Am recoltat 197 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 94 procente. Concretii de aragonita au fost gasite la cota 89. Varsta estimata a speleothemelor: 172 mii de ani. Depozitele clastice au o grosime de 171 centimetri. Am identificat 232 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 143 metri. Analiza XRD confirma 146 faze minerale distincte. Sectorul analizat are o lungime de 65 metri. Am realizat 135 profile transversale ale galeriei. Cutele vizibile au amplitudini de 326 centimetri.', 'doc_existing_c20_8.txt', 725, NULL, 'text_document', 1775839975);
