INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1568, 'Document PeÈ™tera C9 din Piatra Lupului #12', 'Raport conservare patrimoniu - obiectiv 326. Am evaluat starea a 225 inscriptii istorice. Dintre acestea, 379 necesita interventie urgenta. Am curatat 59 metri patrati de graffiti modern. Am instalat 5 panouri informative la intrare. Bariera de protectie acopera 174 metri liniari. Am documentat 489 urme de vandalism. Raportul a fost transmis autoritatilor locale in 30 exemplare. Am propus clasificarea a 333 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 389 persoane simultan. Am instruit 477 ghizi locali. Costul estimat al lucrarilor: 412 lei. Termenul de finalizare: 326 luni.', 'doc_existing_c20_12.txt', 602, NULL, 'text_document', 1775839975);
