INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1570, 'Document PeÈ™tera C9 din Piatra Lupului (Gaura cu VÃ¢jagÄƒu) #1', 'Evidenta resurse hidrologice - punctul 216. Debitul mediu masurat: 266 litri pe secunda. Am efectuat 273 masuratori in perioade diferite. Temperatura apei: 204 grade Celsius, constanta. pH-ul masurat: 500 unitati. Conductivitatea electrica: 269 microsiemensi. Am injectat 83 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 208 ore. Distanta estimata: 92 metri de conducte carstice. Nivelul maxim in sezonul ploios: 323 centimetri peste normal. Am monitorizat 496 izvoare din bazin. Volumul estimat al lacului subteran: 171 metri cubi.', 'doc_existing_c21_1.txt', 547, NULL, 'text_document', 1775839975);
