INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1574, 'Document PeÈ™tera C9 din Piatra Lupului (Gaura cu VÃ¢jagÄƒu) #5', 'Fisa tehnica echipare put - verticala nr. 34. Adancimea: 184 metri. Am instalat 169 spituri din otel inoxidabil. Distanta intre spituri: 110 metri. Lungimea corzii principale: 450 metri. Coarda de siguranta: 384 metri. Am montat 112 protectoare de franghie. Fractionarea se face la 26 metri de buza putului. Deviatia este la 473 metri sub fractionare. Am testat echiparea cu 188 coborari. Ultimul control al spiturilor: acum 320 luni.', 'doc_existing_c21_5.txt', 434, NULL, 'text_document', 1775839975);
