INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1578, 'Document PeÈ™tera D1 din Piatra Lupului #1', 'Raport geologic - profil 340. Stratele de calcar apartin etajului 288. Grosimea medie a stratelor este de 194 centimetri. Fisurile tectonice au un azimut predominant de 74 grade. Am recoltat 103 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 242 procente. Concretii de aragonita au fost gasite la cota 129. Varsta estimata a speleothemelor: 296 mii de ani. Depozitele clastice au o grosime de 128 centimetri. Am identificat 274 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 437 metri. Analiza XRD confirma 22 faze minerale distincte. Sectorul analizat are o lungime de 205 metri. Am realizat 192 profile transversale ale galeriei. Cutele vizibile au amplitudini de 16 centimetri.', 'doc_existing_c22_1.txt', 727, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3692, 22, 'cave', 1578, 1775839975);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1579, 'Document PeÈ™tera D1 din Piatra Lupului #2', 'Proces verbal intalnire club - sedinta nr. 472. Au participat 273 membri. Am discutat 10 puncte pe ordinea de zi. S-a aprobat bugetul de 236 lei pentru trimestrul urmator. Am planificat 371 expeditii in urmatoarele luni. S-au inscris 125 membri noi. Am evaluat 80 rapoarte de explorare. S-a votat achizitionarea de echipament in valoare de 488 lei. Urmatoarea sedinta: peste 43 saptamani. Am desemnat 454 responsabili pentru proiecte.', 'doc_existing_c22_2.txt', 434, NULL, 'text_document', 1775839975);
