INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1580, 'Document PeÈ™tera D1 din Piatra Lupului #3', 'Raport geologic - profil 224. Stratele de calcar apartin etajului 294. Grosimea medie a stratelor este de 474 centimetri. Fisurile tectonice au un azimut predominant de 496 grade. Am recoltat 127 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 114 procente. Concretii de aragonita au fost gasite la cota 119. Varsta estimata a speleothemelor: 462 mii de ani. Depozitele clastice au o grosime de 468 centimetri. Am identificat 169 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 500 metri. Analiza XRD confirma 306 faze minerale distincte. Sectorul analizat are o lungime de 36 metri. Am realizat 218 profile transversale ale galeriei. Cutele vizibile au amplitudini de 81 centimetri.', 'doc_existing_c22_3.txt', 728, NULL, 'text_document', 1775839975);
