INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1581, 'Document PeÈ™tera D1 din Piatra Lupului #4', 'Evidenta resurse hidrologice - punctul 325. Debitul mediu masurat: 148 litri pe secunda. Am efectuat 423 masuratori in perioade diferite. Temperatura apei: 348 grade Celsius, constanta. pH-ul masurat: 336 unitati. Conductivitatea electrica: 44 microsiemensi. Am injectat 351 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 173 ore. Distanta estimata: 329 metri de conducte carstice. Nivelul maxim in sezonul ploios: 25 centimetri peste normal. Am monitorizat 286 izvoare din bazin. Volumul estimat al lacului subteran: 349 metri cubi.', 'doc_existing_c22_4.txt', 547, NULL, 'text_document', 1775839975);
