INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1582, 'Document PeÈ™tera D1 din Piatra Lupului #5', 'Studiu speleogenetic - sectorul 21. Am analizat 110 probe de calcar sub microscop. Varsta estimata a galeriei: 197 milioane de ani. Am identificat 8 faze de speleogeneza. Nivelul freatic actual este la 113 metri adancime. Am corelat cu 426 alte pesteri din zona. Porozitatea medie a rocii: 122 procente. Am realizat 457 sectiuni subtiri din probe. Studiul va fi publicat in volumul 243 al buletinului. Am colaborat cu 225 geologi specialisti.', 'doc_existing_c22_5.txt', 442, NULL, 'text_document', 1775839975);
