INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1586, 'Document PeÈ™tera D1 din Piatra Lupului #9', 'Raport climatologic subteran - statia 371. Senzorul a inregistrat 67 cicluri complete de temperatura. Temperatura medie anuala: 140 grade Celsius. Amplitudinea termica maxima: 254 grade. Umiditatea relativa medie: 38 procente. Concentratia de CO2: 325 ppm. Curentul de aer maxim masurat: 143 metri pe secunda. Directia predominanta a curentului: sector 115. Datalogerul a functionat 57 zile fara intrerupere. Am descarcat 473 megabytes de date brute. Presiunea barometrica la intrare: 326 mbar. Evaporarea masurata: 309 milimetri pe luna. Am comparat datele cu 398 statii meteorologice de suprafata. Raportul complet include 86 grafice si tabele. Monitorizarea continua de 372 luni confirma stabilitatea climatica.', 'doc_existing_c22_9.txt', 714, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3710, 22, 'cave', 1586, 1775839975);
