INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1590, 'Document PeÈ™tera D2 din Piatra Lupului #1', 'Evidenta resurse hidrologice - punctul 168. Debitul mediu masurat: 489 litri pe secunda. Am efectuat 165 masuratori in perioade diferite. Temperatura apei: 240 grade Celsius, constanta. pH-ul masurat: 6 unitati. Conductivitatea electrica: 246 microsiemensi. Am injectat 188 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 342 ore. Distanta estimata: 280 metri de conducte carstice. Nivelul maxim in sezonul ploios: 65 centimetri peste normal. Am monitorizat 459 izvoare din bazin. Volumul estimat al lacului subteran: 207 metri cubi.', 'doc_existing_c23_1.txt', 546, NULL, 'text_document', 1775839975);
