INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1593, 'Document PeÈ™tera D2 din Piatra Lupului #4', 'Raport conservare patrimoniu - obiectiv 423. Am evaluat starea a 410 inscriptii istorice. Dintre acestea, 98 necesita interventie urgenta. Am curatat 273 metri patrati de graffiti modern. Am instalat 416 panouri informative la intrare. Bariera de protectie acopera 245 metri liniari. Am documentat 179 urme de vandalism. Raportul a fost transmis autoritatilor locale in 264 exemplare. Am propus clasificarea a 320 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 265 persoane simultan. Am instruit 341 ghizi locali. Costul estimat al lucrarilor: 361 lei. Termenul de finalizare: 428 luni.', 'doc_existing_c23_4.txt', 605, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3725, 23, 'cave', 1593, 1775839975);
