INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1600, 'Document PeÈ™tera D2 din Piatra Lupului #11', 'Raport climatologic subteran - statia 389. Senzorul a inregistrat 42 cicluri complete de temperatura. Temperatura medie anuala: 102 grade Celsius. Amplitudinea termica maxima: 317 grade. Umiditatea relativa medie: 281 procente. Concentratia de CO2: 396 ppm. Curentul de aer maxim masurat: 70 metri pe secunda. Directia predominanta a curentului: sector 96. Datalogerul a functionat 321 zile fara intrerupere. Am descarcat 304 megabytes de date brute. Presiunea barometrica la intrare: 310 mbar. Evaporarea masurata: 466 milimetri pe luna. Am comparat datele cu 423 statii meteorologice de suprafata. Raportul complet include 73 grafice si tabele. Monitorizarea continua de 21 luni confirma stabilitatea climatica.', 'doc_existing_c23_11.txt', 713, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3740, 23, 'cave', 1600, 1775839975);
