INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1601, 'Document PeÈ™tera D2 din Piatra Lupului #12', 'Studiu speleogenetic - sectorul 349. Am analizat 117 probe de calcar sub microscop. Varsta estimata a galeriei: 312 milioane de ani. Am identificat 476 faze de speleogeneza. Nivelul freatic actual este la 112 metri adancime. Am corelat cu 430 alte pesteri din zona. Porozitatea medie a rocii: 472 procente. Am realizat 153 sectiuni subtiri din probe. Studiul va fi publicat in volumul 453 al buletinului. Am colaborat cu 423 geologi specialisti.', 'doc_existing_c23_12.txt', 445, NULL, 'text_document', 1775839975);
