INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1603, 'Document PeÈ™tera D2 din Piatra Lupului #14', 'Proces verbal intalnire club - sedinta nr. 350. Au participat 230 membri. Am discutat 281 puncte pe ordinea de zi. S-a aprobat bugetul de 382 lei pentru trimestrul urmator. Am planificat 287 expeditii in urmatoarele luni. S-au inscris 478 membri noi. Am evaluat 198 rapoarte de explorare. S-a votat achizitionarea de echipament in valoare de 76 lei. Urmatoarea sedinta: peste 254 saptamani. Am desemnat 368 responsabili pentru proiecte.', 'doc_existing_c23_14.txt', 436, NULL, 'text_document', 1775839975);
