INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1621, 'Document PeÈ™tera D3 din Piatra Lupului #6', 'Raport conservare patrimoniu - obiectiv 254. Am evaluat starea a 161 inscriptii istorice. Dintre acestea, 273 necesita interventie urgenta. Am curatat 405 metri patrati de graffiti modern. Am instalat 135 panouri informative la intrare. Bariera de protectie acopera 55 metri liniari. Am documentat 85 urme de vandalism. Raportul a fost transmis autoritatilor locale in 61 exemplare. Am propus clasificarea a 102 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 90 persoane simultan. Am instruit 15 ghizi locali. Costul estimat al lucrarilor: 115 lei. Termenul de finalizare: 51 luni.', 'doc_existing_c24_6.txt', 600, NULL, 'text_document', 1775839975);
