INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1622, 'Document PeÈ™tera D3 din Piatra Lupului #7', 'Studiu speleogenetic - sectorul 322. Am analizat 68 probe de calcar sub microscop. Varsta estimata a galeriei: 421 milioane de ani. Am identificat 453 faze de speleogeneza. Nivelul freatic actual este la 1 metri adancime. Am corelat cu 314 alte pesteri din zona. Porozitatea medie a rocii: 58 procente. Am realizat 3 sectiuni subtiri din probe. Studiul va fi publicat in volumul 62 al buletinului. Am colaborat cu 461 geologi specialisti.', 'doc_existing_c24_7.txt', 438, NULL, 'text_document', 1775839975);
