INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1626, 'Document PeÈ™tera D3 din Piatra Lupului #11', 'Evidenta resurse hidrologice - punctul 410. Debitul mediu masurat: 425 litri pe secunda. Am efectuat 172 masuratori in perioade diferite. Temperatura apei: 98 grade Celsius, constanta. pH-ul masurat: 334 unitati. Conductivitatea electrica: 21 microsiemensi. Am injectat 159 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 40 ore. Distanta estimata: 458 metri de conducte carstice. Nivelul maxim in sezonul ploios: 50 centimetri peste normal. Am monitorizat 85 izvoare din bazin. Volumul estimat al lacului subteran: 8 metri cubi.', 'doc_existing_c24_11.txt', 542, NULL, 'text_document', 1775839975);
