INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1630, 'Document PeÈ™tera D3 din Piatra Lupului #15', 'Raport climatologic subteran - statia 358. Senzorul a inregistrat 230 cicluri complete de temperatura. Temperatura medie anuala: 116 grade Celsius. Amplitudinea termica maxima: 476 grade. Umiditatea relativa medie: 144 procente. Concentratia de CO2: 241 ppm. Curentul de aer maxim masurat: 263 metri pe secunda. Directia predominanta a curentului: sector 117. Datalogerul a functionat 212 zile fara intrerupere. Am descarcat 418 megabytes de date brute. Presiunea barometrica la intrare: 499 mbar. Evaporarea masurata: 410 milimetri pe luna. Am comparat datele cu 471 statii meteorologice de suprafata. Raportul complet include 255 grafice si tabele. Monitorizarea continua de 86 luni confirma stabilitatea climatica.', 'doc_existing_c24_15.txt', 717, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3814, 24, 'cave', 1630, 1775839975);
