INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1631, 'Document PeÈ™tera D3 din Piatra Lupului #16', 'Evidenta resurse hidrologice - punctul 2. Debitul mediu masurat: 421 litri pe secunda. Am efectuat 314 masuratori in perioade diferite. Temperatura apei: 335 grade Celsius, constanta. pH-ul masurat: 49 unitati. Conductivitatea electrica: 329 microsiemensi. Am injectat 14 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 112 ore. Distanta estimata: 359 metri de conducte carstice. Nivelul maxim in sezonul ploios: 47 centimetri peste normal. Am monitorizat 458 izvoare din bazin. Volumul estimat al lacului subteran: 459 metri cubi.', 'doc_existing_c24_16.txt', 544, NULL, 'text_document', 1775839975);
