INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1632, 'Document PeÈ™tera D3 din Piatra Lupului #17', 'Raport geologic - profil 346. Stratele de calcar apartin etajului 146. Grosimea medie a stratelor este de 445 centimetri. Fisurile tectonice au un azimut predominant de 90 grade. Am recoltat 70 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 430 procente. Concretii de aragonita au fost gasite la cota 343. Varsta estimata a speleothemelor: 247 mii de ani. Depozitele clastice au o grosime de 238 centimetri. Am identificat 285 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 145 metri. Analiza XRD confirma 136 faze minerale distincte. Sectorul analizat are o lungime de 39 metri. Am realizat 312 profile transversale ale galeriei. Cutele vizibile au amplitudini de 472 centimetri.', 'doc_existing_c24_17.txt', 727, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3818, 24, 'cave', 1632, 1775839975);
