INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1633, 'Document PeÈ™tera D3 din Piatra Lupului #18', 'Raport climatologic subteran - statia 139. Senzorul a inregistrat 311 cicluri complete de temperatura. Temperatura medie anuala: 266 grade Celsius. Amplitudinea termica maxima: 169 grade. Umiditatea relativa medie: 291 procente. Concentratia de CO2: 78 ppm. Curentul de aer maxim masurat: 99 metri pe secunda. Directia predominanta a curentului: sector 191. Datalogerul a functionat 500 zile fara intrerupere. Am descarcat 285 megabytes de date brute. Presiunea barometrica la intrare: 284 mbar. Evaporarea masurata: 404 milimetri pe luna. Am comparat datele cu 367 statii meteorologice de suprafata. Raportul complet include 355 grafice si tabele. Monitorizarea continua de 494 luni confirma stabilitatea climatica.', 'doc_existing_c24_18.txt', 716, NULL, 'text_document', 1775839975);
