INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1655, 'Document PeÈ™tera M2 din Piatra Lupului #2', 'Proces verbal intalnire club - sedinta nr. 326. Au participat 424 membri. Am discutat 204 puncte pe ordinea de zi. S-a aprobat bugetul de 115 lei pentru trimestrul urmator. Am planificat 357 expeditii in urmatoarele luni. S-au inscris 51 membri noi. Am evaluat 498 rapoarte de explorare. S-a votat achizitionarea de echipament in valoare de 113 lei. Urmatoarea sedinta: peste 103 saptamani. Am desemnat 211 responsabili pentru proiecte.', 'doc_existing_c26_2.txt', 436, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3872, 26, 'cave', 1655, 1775839975);
