INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1656, 'Document PeÈ™tera M2 din Piatra Lupului #3', 'Raport geologic - profil 435. Stratele de calcar apartin etajului 278. Grosimea medie a stratelor este de 359 centimetri. Fisurile tectonice au un azimut predominant de 206 grade. Am recoltat 478 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 388 procente. Concretii de aragonita au fost gasite la cota 114. Varsta estimata a speleothemelor: 492 mii de ani. Depozitele clastice au o grosime de 39 centimetri. Am identificat 373 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 33 metri. Analiza XRD confirma 424 faze minerale distincte. Sectorul analizat are o lungime de 129 metri. Am realizat 356 profile transversale ale galeriei. Cutele vizibile au amplitudini de 243 centimetri.', 'doc_existing_c26_3.txt', 728, NULL, 'text_document', 1775839975);
