INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1663, 'Document PeÈ™tera M2 din Piatra Lupului #10', 'Evidenta resurse hidrologice - punctul 348. Debitul mediu masurat: 497 litri pe secunda. Am efectuat 340 masuratori in perioade diferite. Temperatura apei: 61 grade Celsius, constanta. pH-ul masurat: 356 unitati. Conductivitatea electrica: 90 microsiemensi. Am injectat 215 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 209 ore. Distanta estimata: 345 metri de conducte carstice. Nivelul maxim in sezonul ploios: 137 centimetri peste normal. Am monitorizat 475 izvoare din bazin. Volumul estimat al lacului subteran: 219 metri cubi.', 'doc_existing_c26_10.txt', 547, NULL, 'text_document', 1775839975);
