INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1673, 'Document PeÈ™tera M3 din Piatra Lupului #1', 'Evidenta resurse hidrologice - punctul 293. Debitul mediu masurat: 26 litri pe secunda. Am efectuat 292 masuratori in perioade diferite. Temperatura apei: 276 grade Celsius, constanta. pH-ul masurat: 75 unitati. Conductivitatea electrica: 7 microsiemensi. Am injectat 199 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 400 ore. Distanta estimata: 34 metri de conducte carstice. Nivelul maxim in sezonul ploios: 152 centimetri peste normal. Am monitorizat 456 izvoare din bazin. Volumul estimat al lacului subteran: 485 metri cubi.', 'doc_existing_c27_1.txt', 544, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3914, 27, 'cave', 1673, 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3915, 116, 'cave_area', 1673, 1775839975);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1674, 'Document PeÈ™tera M3 din Piatra Lupului #2', 'Raport geologic - profil 242. Stratele de calcar apartin etajului 442. Grosimea medie a stratelor este de 96 centimetri. Fisurile tectonice au un azimut predominant de 215 grade. Am recoltat 2 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 326 procente. Concretii de aragonita au fost gasite la cota 211. Varsta estimata a speleothemelor: 268 mii de ani. Depozitele clastice au o grosime de 461 centimetri. Am identificat 272 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 22 metri. Analiza XRD confirma 31 faze minerale distincte. Sectorul analizat are o lungime de 358 metri. Am realizat 35 profile transversale ale galeriei. Cutele vizibile au amplitudini de 405 centimetri.', 'doc_existing_c27_2.txt', 724, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3916, 27, 'cave', 1674, 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3917, 1509, 'cave_place', 1674, 1775839975);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1675, 'Document PeÈ™tera M3 din Piatra Lupului #3', 'Evidenta resurse hidrologice - punctul 478. Debitul mediu masurat: 13 litri pe secunda. Am efectuat 116 masuratori in perioade diferite. Temperatura apei: 441 grade Celsius, constanta. pH-ul masurat: 445 unitati. Conductivitatea electrica: 269 microsiemensi. Am injectat 131 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 309 ore. Distanta estimata: 477 metri de conducte carstice. Nivelul maxim in sezonul ploios: 447 centimetri peste normal. Am monitorizat 52 izvoare din bazin. Volumul estimat al lacului subteran: 389 metri cubi.', 'doc_existing_c27_3.txt', 547, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3918, 27, 'cave', 1675, 1775839975);
