INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1676, 'Document PeÈ™tera M3 din Piatra Lupului #4', 'Raport climatologic subteran - statia 297. Senzorul a inregistrat 410 cicluri complete de temperatura. Temperatura medie anuala: 96 grade Celsius. Amplitudinea termica maxima: 443 grade. Umiditatea relativa medie: 386 procente. Concentratia de CO2: 70 ppm. Curentul de aer maxim masurat: 211 metri pe secunda. Directia predominanta a curentului: sector 328. Datalogerul a functionat 329 zile fara intrerupere. Am descarcat 87 megabytes de date brute. Presiunea barometrica la intrare: 70 mbar. Evaporarea masurata: 23 milimetri pe luna. Am comparat datele cu 151 statii meteorologice de suprafata. Raportul complet include 442 grafice si tabele. Monitorizarea continua de 449 luni confirma stabilitatea climatica.', 'doc_existing_c27_4.txt', 713, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3920, 27, 'cave', 1676, 1775839975);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1677, 'Document PeÈ™tera M3 din Piatra Lupului #5', 'Raport conservare patrimoniu - obiectiv 175. Am evaluat starea a 373 inscriptii istorice. Dintre acestea, 310 necesita interventie urgenta. Am curatat 408 metri patrati de graffiti modern. Am instalat 181 panouri informative la intrare. Bariera de protectie acopera 262 metri liniari. Am documentat 492 urme de vandalism. Raportul a fost transmis autoritatilor locale in 315 exemplare. Am propus clasificarea a 280 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 147 persoane simultan. Am instruit 37 ghizi locali. Costul estimat al lucrarilor: 73 lei. Termenul de finalizare: 405 luni.', 'doc_existing_c27_5.txt', 604, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3921, 27, 'cave', 1677, 1775839975);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1678, 'Document PeÈ™tera M3 din Piatra Lupului #6', 'Proces verbal intalnire club - sedinta nr. 159. Au participat 421 membri. Am discutat 257 puncte pe ordinea de zi. S-a aprobat bugetul de 300 lei pentru trimestrul urmator. Am planificat 152 expeditii in urmatoarele luni. S-au inscris 170 membri noi. Am evaluat 479 rapoarte de explorare. S-a votat achizitionarea de echipament in valoare de 297 lei. Urmatoarea sedinta: peste 109 saptamani. Am desemnat 324 responsabili pentru proiecte.', 'doc_existing_c27_6.txt', 437, NULL, 'text_document', 1775839975);
