INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1684, 'Document PeÈ™tera M3 din Piatra Lupului #12', 'Nota de mentenanta balize - traseul 177. Am verificat 104 balize reflectorizante. Dintre acestea, 18 au fost inlocuite. Am adaugat 175 balize noi in zonele nemarcate. Distanta medie intre balize: 81 metri. Am folosit 236 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 296 metri cu lampa frontala. Am eliminat 436 marcaje vechi si confuze. Traseul total balizat: 71 metri. Urmatoarea verificare: peste 287 luni. Materialul consumat: 432 benzi reflectorizante.', 'doc_existing_c27_12.txt', 482, NULL, 'text_document', 1775839975);
