INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1691, 'Document PeÈ™tera M4 din Piatra Lupului #6', 'Evidenta resurse hidrologice - punctul 195. Debitul mediu masurat: 449 litri pe secunda. Am efectuat 178 masuratori in perioade diferite. Temperatura apei: 447 grade Celsius, constanta. pH-ul masurat: 275 unitati. Conductivitatea electrica: 323 microsiemensi. Am injectat 18 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 207 ore. Distanta estimata: 155 metri de conducte carstice. Nivelul maxim in sezonul ploios: 414 centimetri peste normal. Am monitorizat 47 izvoare din bazin. Volumul estimat al lacului subteran: 268 metri cubi.', 'doc_existing_c28_6.txt', 547, NULL, 'text_document', 1775839975);
