INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1703, 'Document Avenul M5 din Piatra Lupului #2', 'Raport climatologic subteran - statia 297. Senzorul a inregistrat 242 cicluri complete de temperatura. Temperatura medie anuala: 2 grade Celsius. Amplitudinea termica maxima: 473 grade. Umiditatea relativa medie: 3 procente. Concentratia de CO2: 284 ppm. Curentul de aer maxim masurat: 378 metri pe secunda. Directia predominanta a curentului: sector 461. Datalogerul a functionat 139 zile fara intrerupere. Am descarcat 430 megabytes de date brute. Presiunea barometrica la intrare: 57 mbar. Evaporarea masurata: 40 milimetri pe luna. Am comparat datele cu 148 statii meteorologice de suprafata. Raportul complet include 121 grafice si tabele. Monitorizarea continua de 320 luni confirma stabilitatea climatica.', 'doc_existing_c29_2.txt', 712, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3981, 29, 'cave', 1703, 1775839975);
