INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1706, 'Document Avenul M5 din Piatra Lupului #5', 'Raport geologic - profil 216. Stratele de calcar apartin etajului 438. Grosimea medie a stratelor este de 216 centimetri. Fisurile tectonice au un azimut predominant de 451 grade. Am recoltat 471 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 20 procente. Concretii de aragonita au fost gasite la cota 2. Varsta estimata a speleothemelor: 350 mii de ani. Depozitele clastice au o grosime de 421 centimetri. Am identificat 231 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 12 metri. Analiza XRD confirma 454 faze minerale distincte. Sectorul analizat are o lungime de 4 metri. Am realizat 259 profile transversale ale galeriei. Cutele vizibile au amplitudini de 230 centimetri.', 'doc_existing_c29_5.txt', 724, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (3990, 29, 'cave', 1706, 1775839975);
