INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1711, 'Document Avenul M5 din Piatra Lupului #10', 'Fisa tehnica echipare put - verticala nr. 339. Adancimea: 451 metri. Am instalat 376 spituri din otel inoxidabil. Distanta intre spituri: 21 metri. Lungimea corzii principale: 338 metri. Coarda de siguranta: 454 metri. Am montat 218 protectoare de franghie. Fractionarea se face la 204 metri de buza putului. Deviatia este la 398 metri sub fractionare. Am testat echiparea cu 166 coborari. Ultimul control al spiturilor: acum 37 luni.', 'doc_existing_c29_10.txt', 434, NULL, 'text_document', 1775839975);
