INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1712, 'Document Avenul M5 din Piatra Lupului #11', 'Proces verbal intalnire club - sedinta nr. 297. Au participat 320 membri. Am discutat 310 puncte pe ordinea de zi. S-a aprobat bugetul de 235 lei pentru trimestrul urmator. Am planificat 460 expeditii in urmatoarele luni. S-au inscris 255 membri noi. Am evaluat 474 rapoarte de explorare. S-a votat achizitionarea de echipament in valoare de 156 lei. Urmatoarea sedinta: peste 301 saptamani. Am desemnat 128 responsabili pentru proiecte.', 'doc_existing_c29_11.txt', 437, NULL, 'text_document', 1775839975);
