INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1728, 'Document Avenul X2 din Piatra Lupului #1', 'Nota de mentenanta balize - traseul 207. Am verificat 117 balize reflectorizante. Dintre acestea, 161 au fost inlocuite. Am adaugat 217 balize noi in zonele nemarcate. Distanta medie intre balize: 143 metri. Am folosit 358 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 178 metri cu lampa frontala. Am eliminat 320 marcaje vechi si confuze. Traseul total balizat: 113 metri. Urmatoarea verificare: peste 307 luni. Materialul consumat: 240 benzi reflectorizante.', 'doc_existing_c30_1.txt', 485, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4046, 30, 'cave', 1728, 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4047, 1738, 'cave_place', 1728, 1775839975);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1729, 'Document Avenul X2 din Piatra Lupului #2', 'Studiu speleogenetic - sectorul 68. Am analizat 482 probe de calcar sub microscop. Varsta estimata a galeriei: 325 milioane de ani. Am identificat 375 faze de speleogeneza. Nivelul freatic actual este la 413 metri adancime. Am corelat cu 370 alte pesteri din zona. Porozitatea medie a rocii: 302 procente. Am realizat 93 sectiuni subtiri din probe. Studiul va fi publicat in volumul 456 al buletinului. Am colaborat cu 191 geologi specialisti.', 'doc_existing_c30_2.txt', 443, NULL, 'text_document', 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4048, 30, 'cave', 1729, 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4049, 127, 'cave_area', 1729, 1775839975);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4050, 1721, 'cave_place', 1729, 1775839975);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1730, 'Document Avenul X2 din Piatra Lupului #3', 'Nota de mentenanta balize - traseul 148. Am verificat 341 balize reflectorizante. Dintre acestea, 455 au fost inlocuite. Am adaugat 235 balize noi in zonele nemarcate. Distanta medie intre balize: 211 metri. Am folosit 370 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 468 metri cu lampa frontala. Am eliminat 63 marcaje vechi si confuze. Traseul total balizat: 242 metri. Urmatoarea verificare: peste 331 luni. Materialul consumat: 304 benzi reflectorizante.', 'doc_existing_c30_3.txt', 484, NULL, 'text_document', 1775839975);
