INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1731, 'Document Avenul X2 din Piatra Lupului #4', 'Studiu speleogenetic - sectorul 248. Am analizat 475 probe de calcar sub microscop. Varsta estimata a galeriei: 454 milioane de ani. Am identificat 56 faze de speleogeneza. Nivelul freatic actual este la 278 metri adancime. Am corelat cu 5 alte pesteri din zona. Porozitatea medie a rocii: 160 procente. Am realizat 42 sectiuni subtiri din probe. Studiul va fi publicat in volumul 455 al buletinului. Am colaborat cu 384 geologi specialisti.', 'doc_existing_c30_4.txt', 441, NULL, 'text_document', 1775839975);
