INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1741, 'Document PeÈ™tera X3 din Piatra Lupului #3', 'Nota de mentenanta balize - traseul 411. Am verificat 99 balize reflectorizante. Dintre acestea, 455 au fost inlocuite. Am adaugat 10 balize noi in zonele nemarcate. Distanta medie intre balize: 361 metri. Am folosit 488 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 249 metri cu lampa frontala. Am eliminat 262 marcaje vechi si confuze. Traseul total balizat: 246 metri. Urmatoarea verificare: peste 494 luni. Materialul consumat: 476 benzi reflectorizante.', 'doc_existing_c31_3.txt', 483, NULL, 'text_document', 1775839976);
