INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1742, 'Document PeÈ™tera X3 din Piatra Lupului #4', 'Studiu speleogenetic - sectorul 134. Am analizat 56 probe de calcar sub microscop. Varsta estimata a galeriei: 253 milioane de ani. Am identificat 175 faze de speleogeneza. Nivelul freatic actual este la 476 metri adancime. Am corelat cu 254 alte pesteri din zona. Porozitatea medie a rocii: 415 procente. Am realizat 261 sectiuni subtiri din probe. Studiul va fi publicat in volumul 34 al buletinului. Am colaborat cu 271 geologi specialisti.', 'doc_existing_c31_4.txt', 443, NULL, 'text_document', 1775839976);
