INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1745, 'Document PeÈ™tera X3 din Piatra Lupului #7', 'Raport climatologic subteran - statia 60. Senzorul a inregistrat 492 cicluri complete de temperatura. Temperatura medie anuala: 392 grade Celsius. Amplitudinea termica maxima: 43 grade. Umiditatea relativa medie: 25 procente. Concentratia de CO2: 424 ppm. Curentul de aer maxim masurat: 21 metri pe secunda. Directia predominanta a curentului: sector 198. Datalogerul a functionat 254 zile fara intrerupere. Am descarcat 446 megabytes de date brute. Presiunea barometrica la intrare: 231 mbar. Evaporarea masurata: 293 milimetri pe luna. Am comparat datele cu 465 statii meteorologice de suprafata. Raportul complet include 420 grafice si tabele. Monitorizarea continua de 96 luni confirma stabilitatea climatica.', 'doc_existing_c31_7.txt', 713, NULL, 'text_document', 1775839976);
