INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1747, 'Document PeÈ™tera X3 din Piatra Lupului #9', 'Raport conservare patrimoniu - obiectiv 380. Am evaluat starea a 283 inscriptii istorice. Dintre acestea, 370 necesita interventie urgenta. Am curatat 149 metri patrati de graffiti modern. Am instalat 143 panouri informative la intrare. Bariera de protectie acopera 138 metri liniari. Am documentat 398 urme de vandalism. Raportul a fost transmis autoritatilor locale in 301 exemplare. Am propus clasificarea a 494 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 200 persoane simultan. Am instruit 403 ghizi locali. Costul estimat al lucrarilor: 470 lei. Termenul de finalizare: 86 luni.', 'doc_existing_c31_9.txt', 605, NULL, 'text_document', 1775839976);
