INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1749, 'Document PeÈ™tera X3 din Piatra Lupului #11', 'Raport geologic - profil 264. Stratele de calcar apartin etajului 134. Grosimea medie a stratelor este de 169 centimetri. Fisurile tectonice au un azimut predominant de 79 grade. Am recoltat 440 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 220 procente. Concretii de aragonita au fost gasite la cota 285. Varsta estimata a speleothemelor: 212 mii de ani. Depozitele clastice au o grosime de 264 centimetri. Am identificat 17 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 320 metri. Analiza XRD confirma 462 faze minerale distincte. Sectorul analizat are o lungime de 340 metri. Am realizat 430 profile transversale ale galeriei. Cutele vizibile au amplitudini de 149 centimetri.', 'doc_existing_c31_11.txt', 728, NULL, 'text_document', 1775839976);
