INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1751, 'Document PeÈ™tera X3 din Piatra Lupului #13', 'Raport geologic - profil 299. Stratele de calcar apartin etajului 56. Grosimea medie a stratelor este de 462 centimetri. Fisurile tectonice au un azimut predominant de 421 grade. Am recoltat 83 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 227 procente. Concretii de aragonita au fost gasite la cota 336. Varsta estimata a speleothemelor: 32 mii de ani. Depozitele clastice au o grosime de 330 centimetri. Am identificat 295 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 362 metri. Analiza XRD confirma 204 faze minerale distincte. Sectorul analizat are o lungime de 453 metri. Am realizat 24 profile transversale ale galeriei. Cutele vizibile au amplitudini de 442 centimetri.', 'doc_existing_c31_13.txt', 726, NULL, 'text_document', 1775839976);
