INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1752, 'Document PeÈ™tera X3 din Piatra Lupului #14', 'Evidenta resurse hidrologice - punctul 75. Debitul mediu masurat: 277 litri pe secunda. Am efectuat 387 masuratori in perioade diferite. Temperatura apei: 255 grade Celsius, constanta. pH-ul masurat: 223 unitati. Conductivitatea electrica: 73 microsiemensi. Am injectat 488 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 347 ore. Distanta estimata: 66 metri de conducte carstice. Nivelul maxim in sezonul ploios: 330 centimetri peste normal. Am monitorizat 90 izvoare din bazin. Volumul estimat al lacului subteran: 142 metri cubi.', 'doc_existing_c31_14.txt', 545, NULL, 'text_document', 1775839976);
