INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1764, 'Document PeÈ™tera X4 din Piatra Lupului #1', 'Evaluare risc - sectorul 332. Am identificat 398 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 173 centimetri. Nivelul apei poate creste cu 197 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 77 metri. Am instalat 117 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 238 minute. Echipamentul de prim ajutor este pozitionat la statia 42. Am testat comunicarea radio in 423 puncte critice. Semnalul radio este pierdut dupa 354 metri de la intrare. Am recomandat echipa minima de 79 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 12 ore. Protocoalele de securitate au fost revizuite de 50 ori anul acesta. Ultimul incident a avut loc cu 232 luni in urma. Am efectuat 498 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 406.', 'doc_existing_c32_1.txt', 886, NULL, 'text_document', 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4137, 32, 'cave', 1764, 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4138, 138, 'cave_area', 1764, 1775839976);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1765, 'Document PeÈ™tera X4 din Piatra Lupului #2', 'Proces verbal intalnire club - sedinta nr. 337. Au participat 407 membri. Am discutat 305 puncte pe ordinea de zi. S-a aprobat bugetul de 11 lei pentru trimestrul urmator. Am planificat 132 expeditii in urmatoarele luni. S-au inscris 433 membri noi. Am evaluat 108 rapoarte de explorare. S-a votat achizitionarea de echipament in valoare de 474 lei. Urmatoarea sedinta: peste 383 saptamani. Am desemnat 268 responsabili pentru proiecte.', 'doc_existing_c32_2.txt', 436, NULL, 'text_document', 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4139, 32, 'cave', 1765, 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4140, 1847, 'cave_place', 1765, 1775839976);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1766, 'Document PeÈ™tera X4 din Piatra Lupului #3', 'Raport conservare patrimoniu - obiectiv 125. Am evaluat starea a 210 inscriptii istorice. Dintre acestea, 321 necesita interventie urgenta. Am curatat 23 metri patrati de graffiti modern. Am instalat 303 panouri informative la intrare. Bariera de protectie acopera 448 metri liniari. Am documentat 433 urme de vandalism. Raportul a fost transmis autoritatilor locale in 301 exemplare. Am propus clasificarea a 336 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 191 persoane simultan. Am instruit 438 ghizi locali. Costul estimat al lucrarilor: 275 lei. Termenul de finalizare: 194 luni.', 'doc_existing_c32_3.txt', 605, NULL, 'text_document', 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4141, 32, 'cave', 1766, 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4142, 1893, 'cave_place', 1766, 1775839976);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1767, 'Document PeÈ™tera X4 din Piatra Lupului #4', 'Studiu speleogenetic - sectorul 261. Am analizat 114 probe de calcar sub microscop. Varsta estimata a galeriei: 222 milioane de ani. Am identificat 468 faze de speleogeneza. Nivelul freatic actual este la 236 metri adancime. Am corelat cu 321 alte pesteri din zona. Porozitatea medie a rocii: 409 procente. Am realizat 196 sectiuni subtiri din probe. Studiul va fi publicat in volumul 500 al buletinului. Am colaborat cu 175 geologi specialisti.', 'doc_existing_c32_4.txt', 445, NULL, 'text_document', 1775839976);
