INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1770, 'Document PeÈ™tera X4 din Piatra Lupului #7', 'Raport climatologic subteran - statia 10. Senzorul a inregistrat 391 cicluri complete de temperatura. Temperatura medie anuala: 325 grade Celsius. Amplitudinea termica maxima: 72 grade. Umiditatea relativa medie: 213 procente. Concentratia de CO2: 313 ppm. Curentul de aer maxim masurat: 107 metri pe secunda. Directia predominanta a curentului: sector 114. Datalogerul a functionat 362 zile fara intrerupere. Am descarcat 479 megabytes de date brute. Presiunea barometrica la intrare: 114 mbar. Evaporarea masurata: 332 milimetri pe luna. Am comparat datele cu 440 statii meteorologice de suprafata. Raportul complet include 2 grafice si tabele. Monitorizarea continua de 262 luni confirma stabilitatea climatica.', 'doc_existing_c32_7.txt', 714, NULL, 'text_document', 1775839976);
