INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1782, 'Document PeÈ™tera X6 din Piatra Lupului #3', 'Raport geologic - profil 102. Stratele de calcar apartin etajului 136. Grosimea medie a stratelor este de 136 centimetri. Fisurile tectonice au un azimut predominant de 450 grade. Am recoltat 313 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 374 procente. Concretii de aragonita au fost gasite la cota 303. Varsta estimata a speleothemelor: 307 mii de ani. Depozitele clastice au o grosime de 326 centimetri. Am identificat 20 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 226 metri. Analiza XRD confirma 324 faze minerale distincte. Sectorul analizat are o lungime de 216 metri. Am realizat 226 profile transversale ale galeriei. Cutele vizibile au amplitudini de 143 centimetri.', 'doc_existing_c33_3.txt', 729, NULL, 'text_document', 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4179, 33, 'cave', 1782, 1775839976);
