INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1800, 'Document PeÈ™tera X8 din Piatra Lupului #4', 'Fisa tehnica echipare put - verticala nr. 9. Adancimea: 480 metri. Am instalat 448 spituri din otel inoxidabil. Distanta intre spituri: 216 metri. Lungimea corzii principale: 318 metri. Coarda de siguranta: 141 metri. Am montat 157 protectoare de franghie. Fractionarea se face la 51 metri de buza putului. Deviatia este la 158 metri sub fractionare. Am testat echiparea cu 190 coborari. Ultimul control al spiturilor: acum 191 luni.', 'doc_existing_c35_4.txt', 433, NULL, 'text_document', 1775839976);
