INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1803, 'Document PeÈ™tera X8 din Piatra Lupului #7', 'Raport climatologic subteran - statia 387. Senzorul a inregistrat 117 cicluri complete de temperatura. Temperatura medie anuala: 130 grade Celsius. Amplitudinea termica maxima: 118 grade. Umiditatea relativa medie: 146 procente. Concentratia de CO2: 372 ppm. Curentul de aer maxim masurat: 100 metri pe secunda. Directia predominanta a curentului: sector 74. Datalogerul a functionat 492 zile fara intrerupere. Am descarcat 223 megabytes de date brute. Presiunea barometrica la intrare: 24 mbar. Evaporarea masurata: 77 milimetri pe luna. Am comparat datele cu 359 statii meteorologice de suprafata. Raportul complet include 200 grafice si tabele. Monitorizarea continua de 460 luni confirma stabilitatea climatica.', 'doc_existing_c35_7.txt', 715, NULL, 'text_document', 1775839976);
