INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1808, 'Document PeÈ™tera X8 din Piatra Lupului #12', 'Raport climatologic subteran - statia 291. Senzorul a inregistrat 424 cicluri complete de temperatura. Temperatura medie anuala: 20 grade Celsius. Amplitudinea termica maxima: 255 grade. Umiditatea relativa medie: 415 procente. Concentratia de CO2: 225 ppm. Curentul de aer maxim masurat: 270 metri pe secunda. Directia predominanta a curentului: sector 52. Datalogerul a functionat 347 zile fara intrerupere. Am descarcat 186 megabytes de date brute. Presiunea barometrica la intrare: 58 mbar. Evaporarea masurata: 456 milimetri pe luna. Am comparat datele cu 223 statii meteorologice de suprafata. Raportul complet include 228 grafice si tabele. Monitorizarea continua de 354 luni confirma stabilitatea climatica.', 'doc_existing_c35_12.txt', 715, NULL, 'text_document', 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4242, 35, 'cave', 1808, 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4243, 2155, 'cave_place', 1808, 1775839976);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1809, 'Document PeÈ™tera X8 din Piatra Lupului #13', 'Raport geologic - profil 436. Stratele de calcar apartin etajului 40. Grosimea medie a stratelor este de 66 centimetri. Fisurile tectonice au un azimut predominant de 123 grade. Am recoltat 141 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 411 procente. Concretii de aragonita au fost gasite la cota 184. Varsta estimata a speleothemelor: 386 mii de ani. Depozitele clastice au o grosime de 173 centimetri. Am identificat 37 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 495 metri. Analiza XRD confirma 81 faze minerale distincte. Sectorul analizat are o lungime de 461 metri. Am realizat 129 profile transversale ale galeriei. Cutele vizibile au amplitudini de 240 centimetri.', 'doc_existing_c35_13.txt', 726, NULL, 'text_document', 1775839976);
