INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1827, 'Document PeÈ™tera X9 din Piatra Lupului #1', 'Evidenta resurse hidrologice - punctul 374. Debitul mediu masurat: 5 litri pe secunda. Am efectuat 445 masuratori in perioade diferite. Temperatura apei: 160 grade Celsius, constanta. pH-ul masurat: 423 unitati. Conductivitatea electrica: 43 microsiemensi. Am injectat 262 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 165 ore. Distanta estimata: 358 metri de conducte carstice. Nivelul maxim in sezonul ploios: 113 centimetri peste normal. Am monitorizat 429 izvoare din bazin. Volumul estimat al lacului subteran: 222 metri cubi.', 'doc_existing_c36_1.txt', 546, NULL, 'text_document', 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4282, 36, 'cave', 1827, 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4283, 158, 'cave_area', 1827, 1775839976);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1828, 'Document PeÈ™tera X9 din Piatra Lupului #2', 'Raport geologic - profil 102. Stratele de calcar apartin etajului 75. Grosimea medie a stratelor este de 219 centimetri. Fisurile tectonice au un azimut predominant de 445 grade. Am recoltat 53 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 263 procente. Concretii de aragonita au fost gasite la cota 39. Varsta estimata a speleothemelor: 472 mii de ani. Depozitele clastice au o grosime de 148 centimetri. Am identificat 290 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 103 metri. Analiza XRD confirma 395 faze minerale distincte. Sectorul analizat are o lungime de 104 metri. Am realizat 181 profile transversale ale galeriei. Cutele vizibile au amplitudini de 474 centimetri.', 'doc_existing_c36_2.txt', 727, NULL, 'text_document', 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4284, 36, 'cave', 1828, 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4285, 2202, 'cave_place', 1828, 1775839976);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1829, 'Document PeÈ™tera X9 din Piatra Lupului #3', 'Raport conservare patrimoniu - obiectiv 145. Am evaluat starea a 151 inscriptii istorice. Dintre acestea, 87 necesita interventie urgenta. Am curatat 216 metri patrati de graffiti modern. Am instalat 249 panouri informative la intrare. Bariera de protectie acopera 280 metri liniari. Am documentat 215 urme de vandalism. Raportul a fost transmis autoritatilor locale in 500 exemplare. Am propus clasificarea a 114 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 273 persoane simultan. Am instruit 165 ghizi locali. Costul estimat al lucrarilor: 463 lei. Termenul de finalizare: 217 luni.', 'doc_existing_c36_3.txt', 605, NULL, 'text_document', 1775839976);
