INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1851, 'Document PeÈ™tera E1 din Piatra Lupului #7', 'Nota de mentenanta balize - traseul 448. Am verificat 87 balize reflectorizante. Dintre acestea, 144 au fost inlocuite. Am adaugat 217 balize noi in zonele nemarcate. Distanta medie intre balize: 64 metri. Am folosit 307 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 262 metri cu lampa frontala. Am eliminat 49 marcaje vechi si confuze. Traseul total balizat: 187 metri. Urmatoarea verificare: peste 87 luni. Materialul consumat: 458 benzi reflectorizante.', 'doc_existing_c37_7.txt', 481, NULL, 'text_document', 1775839976);
