INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1864, 'Document PeÈ™tera E3 din Piatra Lupului #1', 'Raport geologic - profil 304. Stratele de calcar apartin etajului 388. Grosimea medie a stratelor este de 463 centimetri. Fisurile tectonice au un azimut predominant de 401 grade. Am recoltat 342 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 22 procente. Concretii de aragonita au fost gasite la cota 248. Varsta estimata a speleothemelor: 246 mii de ani. Depozitele clastice au o grosime de 8 centimetri. Am identificat 86 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 139 metri. Analiza XRD confirma 154 faze minerale distincte. Sectorul analizat are o lungime de 346 metri. Am realizat 362 profile transversale ale galeriei. Cutele vizibile au amplitudini de 39 centimetri.', 'doc_existing_c38_1.txt', 725, NULL, 'text_document', 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4372, 38, 'cave', 1864, 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4373, 169, 'cave_area', 1864, 1775839976);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1865, 'Document PeÈ™tera E3 din Piatra Lupului #2', 'Studiu speleogenetic - sectorul 46. Am analizat 253 probe de calcar sub microscop. Varsta estimata a galeriei: 78 milioane de ani. Am identificat 243 faze de speleogeneza. Nivelul freatic actual este la 422 metri adancime. Am corelat cu 297 alte pesteri din zona. Porozitatea medie a rocii: 327 procente. Am realizat 237 sectiuni subtiri din probe. Studiul va fi publicat in volumul 205 al buletinului. Am colaborat cu 307 geologi specialisti.', 'doc_existing_c38_2.txt', 443, NULL, 'text_document', 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4374, 38, 'cave', 1865, 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4375, 169, 'cave_area', 1865, 1775839976);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1866, 'Document PeÈ™tera E3 din Piatra Lupului #3', 'Raport climatologic subteran - statia 86. Senzorul a inregistrat 67 cicluri complete de temperatura. Temperatura medie anuala: 131 grade Celsius. Amplitudinea termica maxima: 455 grade. Umiditatea relativa medie: 428 procente. Concentratia de CO2: 311 ppm. Curentul de aer maxim masurat: 221 metri pe secunda. Directia predominanta a curentului: sector 302. Datalogerul a functionat 260 zile fara intrerupere. Am descarcat 247 megabytes de date brute. Presiunea barometrica la intrare: 117 mbar. Evaporarea masurata: 475 milimetri pe luna. Am comparat datele cu 87 statii meteorologice de suprafata. Raportul complet include 35 grafice si tabele. Monitorizarea continua de 488 luni confirma stabilitatea climatica.', 'doc_existing_c38_3.txt', 714, NULL, 'text_document', 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4376, 38, 'cave', 1866, 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4377, 2351, 'cave_place', 1866, 1775839976);
