INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1869, 'Document PeÈ™tera E3 din Piatra Lupului #6', 'Nota de mentenanta balize - traseul 180. Am verificat 80 balize reflectorizante. Dintre acestea, 447 au fost inlocuite. Am adaugat 256 balize noi in zonele nemarcate. Distanta medie intre balize: 368 metri. Am folosit 63 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 241 metri cu lampa frontala. Am eliminat 328 marcaje vechi si confuze. Traseul total balizat: 197 metri. Urmatoarea verificare: peste 496 luni. Materialul consumat: 334 benzi reflectorizante.', 'doc_existing_c38_6.txt', 483, NULL, 'text_document', 1775839976);
