INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1871, 'Document PeÈ™tera E3 din Piatra Lupului #8', 'Fisa tehnica echipare put - verticala nr. 146. Adancimea: 126 metri. Am instalat 87 spituri din otel inoxidabil. Distanta intre spituri: 409 metri. Lungimea corzii principale: 444 metri. Coarda de siguranta: 70 metri. Am montat 344 protectoare de franghie. Fractionarea se face la 306 metri de buza putului. Deviatia este la 409 metri sub fractionare. Am testat echiparea cu 108 coborari. Ultimul control al spiturilor: acum 63 luni.', 'doc_existing_c38_8.txt', 433, NULL, 'text_document', 1775839976);
