INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1896, 'Document PeÈ™tera E4 din Piatra Lupului #1', 'Evaluare risc - sectorul 64. Am identificat 267 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 112 centimetri. Nivelul apei poate creste cu 476 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 405 metri. Am instalat 38 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 85 minute. Echipamentul de prim ajutor este pozitionat la statia 37. Am testat comunicarea radio in 425 puncte critice. Semnalul radio este pierdut dupa 349 metri de la intrare. Am recomandat echipa minima de 402 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 181 ore. Protocoalele de securitate au fost revizuite de 418 ori anul acesta. Ultimul incident a avut loc cu 124 luni in urma. Am efectuat 264 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 4.', 'doc_existing_c39_1.txt', 885, NULL, 'text_document', 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4440, 39, 'cave', 1896, 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4441, 171, 'cave_area', 1896, 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4442, 2375, 'cave_place', 1896, 1775839976);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1897, 'Document PeÈ™tera E4 din Piatra Lupului #2', 'Evidenta resurse hidrologice - punctul 310. Debitul mediu masurat: 271 litri pe secunda. Am efectuat 317 masuratori in perioade diferite. Temperatura apei: 122 grade Celsius, constanta. pH-ul masurat: 202 unitati. Conductivitatea electrica: 490 microsiemensi. Am injectat 272 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 23 ore. Distanta estimata: 163 metri de conducte carstice. Nivelul maxim in sezonul ploios: 457 centimetri peste normal. Am monitorizat 348 izvoare din bazin. Volumul estimat al lacului subteran: 332 metri cubi.', 'doc_existing_c39_2.txt', 548, NULL, 'text_document', 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4443, 39, 'cave', 1897, 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4444, 172, 'cave_area', 1897, 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4445, 2387, 'cave_place', 1897, 1775839976);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1898, 'Document PeÈ™tera E4 din Piatra Lupului #3', 'Raport conservare patrimoniu - obiectiv 328. Am evaluat starea a 347 inscriptii istorice. Dintre acestea, 276 necesita interventie urgenta. Am curatat 286 metri patrati de graffiti modern. Am instalat 346 panouri informative la intrare. Bariera de protectie acopera 166 metri liniari. Am documentat 425 urme de vandalism. Raportul a fost transmis autoritatilor locale in 342 exemplare. Am propus clasificarea a 273 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 309 persoane simultan. Am instruit 228 ghizi locali. Costul estimat al lucrarilor: 432 lei. Termenul de finalizare: 450 luni.', 'doc_existing_c39_3.txt', 606, NULL, 'text_document', 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4446, 39, 'cave', 1898, 1775839976);
