INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1911, 'Document PeÈ™tera E5 din Piatra Lupului #3', 'Proces verbal intalnire club - sedinta nr. 164. Au participat 478 membri. Am discutat 196 puncte pe ordinea de zi. S-a aprobat bugetul de 14 lei pentru trimestrul urmator. Am planificat 401 expeditii in urmatoarele luni. S-au inscris 360 membri noi. Am evaluat 112 rapoarte de explorare. S-a votat achizitionarea de echipament in valoare de 356 lei. Urmatoarea sedinta: peste 138 saptamani. Am desemnat 226 responsabili pentru proiecte.', 'doc_existing_c40_3.txt', 436, NULL, 'text_document', 1775839976);
