INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1912, 'Document PeÈ™tera E5 din Piatra Lupului #4', 'Evaluare risc - sectorul 467. Am identificat 300 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 398 centimetri. Nivelul apei poate creste cu 499 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 236 metri. Am instalat 147 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 118 minute. Echipamentul de prim ajutor este pozitionat la statia 426. Am testat comunicarea radio in 72 puncte critice. Semnalul radio este pierdut dupa 480 metri de la intrare. Am recomandat echipa minima de 125 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 414 ore. Protocoalele de securitate au fost revizuite de 142 ori anul acesta. Ultimul incident a avut loc cu 467 luni in urma. Am efectuat 100 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 447.', 'doc_existing_c40_4.txt', 890, NULL, 'text_document', 1775839976);
