INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1913, 'Document PeÈ™tera E5 din Piatra Lupului #5', 'Raport climatologic subteran - statia 6. Senzorul a inregistrat 305 cicluri complete de temperatura. Temperatura medie anuala: 258 grade Celsius. Amplitudinea termica maxima: 296 grade. Umiditatea relativa medie: 400 procente. Concentratia de CO2: 468 ppm. Curentul de aer maxim masurat: 6 metri pe secunda. Directia predominanta a curentului: sector 221. Datalogerul a functionat 177 zile fara intrerupere. Am descarcat 498 megabytes de date brute. Presiunea barometrica la intrare: 263 mbar. Evaporarea masurata: 418 milimetri pe luna. Am comparat datele cu 355 statii meteorologice de suprafata. Raportul complet include 472 grafice si tabele. Monitorizarea continua de 378 luni confirma stabilitatea climatica.', 'doc_existing_c40_5.txt', 714, NULL, 'text_document', 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4482, 40, 'cave', 1913, 1775839976);
