INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1914, 'Document PeÈ™tera E5 din Piatra Lupului #6', 'Raport geologic - profil 110. Stratele de calcar apartin etajului 489. Grosimea medie a stratelor este de 234 centimetri. Fisurile tectonice au un azimut predominant de 156 grade. Am recoltat 174 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 119 procente. Concretii de aragonita au fost gasite la cota 148. Varsta estimata a speleothemelor: 184 mii de ani. Depozitele clastice au o grosime de 19 centimetri. Am identificat 390 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 130 metri. Analiza XRD confirma 191 faze minerale distincte. Sectorul analizat are o lungime de 312 metri. Am realizat 38 profile transversale ale galeriei. Cutele vizibile au amplitudini de 487 centimetri.', 'doc_existing_c40_6.txt', 728, NULL, 'text_document', 1775839976);
