INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1918, 'Document PeÈ™tera E6 din Piatra Lupului #2', 'Nota de mentenanta balize - traseul 282. Am verificat 463 balize reflectorizante. Dintre acestea, 66 au fost inlocuite. Am adaugat 295 balize noi in zonele nemarcate. Distanta medie intre balize: 425 metri. Am folosit 217 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 12 metri cu lampa frontala. Am eliminat 485 marcaje vechi si confuze. Traseul total balizat: 45 metri. Urmatoarea verificare: peste 131 luni. Materialul consumat: 104 benzi reflectorizante.', 'doc_existing_c41_2.txt', 482, NULL, 'text_document', 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4495, 41, 'cave', 1918, 1775839976);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1919, 'Document PeÈ™tera E6 din Piatra Lupului #3', 'Raport conservare patrimoniu - obiectiv 286. Am evaluat starea a 308 inscriptii istorice. Dintre acestea, 442 necesita interventie urgenta. Am curatat 136 metri patrati de graffiti modern. Am instalat 171 panouri informative la intrare. Bariera de protectie acopera 280 metri liniari. Am documentat 307 urme de vandalism. Raportul a fost transmis autoritatilor locale in 213 exemplare. Am propus clasificarea a 67 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 133 persoane simultan. Am instruit 68 ghizi locali. Costul estimat al lucrarilor: 98 lei. Termenul de finalizare: 358 luni.', 'doc_existing_c41_3.txt', 603, NULL, 'text_document', 1775839976);
