INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1920, 'Document PeÈ™tera E6 din Piatra Lupului #4', 'Evaluare risc - sectorul 4. Am identificat 417 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 324 centimetri. Nivelul apei poate creste cu 326 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 268 metri. Am instalat 65 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 38 minute. Echipamentul de prim ajutor este pozitionat la statia 353. Am testat comunicarea radio in 48 puncte critice. Semnalul radio este pierdut dupa 419 metri de la intrare. Am recomandat echipa minima de 54 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 153 ore. Protocoalele de securitate au fost revizuite de 389 ori anul acesta. Ultimul incident a avut loc cu 413 luni in urma. Am efectuat 301 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 420.', 'doc_existing_c41_4.txt', 885, NULL, 'text_document', 1775839976);
