INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1922, 'Document PeÈ™tera E6 din Piatra Lupului #6', 'Studiu speleogenetic - sectorul 195. Am analizat 439 probe de calcar sub microscop. Varsta estimata a galeriei: 197 milioane de ani. Am identificat 218 faze de speleogeneza. Nivelul freatic actual este la 214 metri adancime. Am corelat cu 105 alte pesteri din zona. Porozitatea medie a rocii: 420 procente. Am realizat 265 sectiuni subtiri din probe. Studiul va fi publicat in volumul 71 al buletinului. Am colaborat cu 440 geologi specialisti.', 'doc_existing_c41_6.txt', 444, NULL, 'text_document', 1775839976);
