INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1926, 'Document PeÈ™tera F1 din Piatra Lupului #1', 'Evidenta resurse hidrologice - punctul 351. Debitul mediu masurat: 448 litri pe secunda. Am efectuat 370 masuratori in perioade diferite. Temperatura apei: 380 grade Celsius, constanta. pH-ul masurat: 159 unitati. Conductivitatea electrica: 10 microsiemensi. Am injectat 318 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 387 ore. Distanta estimata: 379 metri de conducte carstice. Nivelul maxim in sezonul ploios: 245 centimetri peste normal. Am monitorizat 126 izvoare din bazin. Volumul estimat al lacului subteran: 225 metri cubi.', 'doc_existing_c42_1.txt', 548, NULL, 'text_document', 1775839976);
