INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1933, 'Document PeÈ™tera F1 din Piatra Lupului #8', 'Proces verbal intalnire club - sedinta nr. 177. Au participat 124 membri. Am discutat 334 puncte pe ordinea de zi. S-a aprobat bugetul de 111 lei pentru trimestrul urmator. Am planificat 433 expeditii in urmatoarele luni. S-au inscris 51 membri noi. Am evaluat 109 rapoarte de explorare. S-a votat achizitionarea de echipament in valoare de 485 lei. Urmatoarea sedinta: peste 226 saptamani. Am desemnat 96 responsabili pentru proiecte.', 'doc_existing_c42_8.txt', 435, NULL, 'text_document', 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4531, 42, 'cave', 1933, 1775839976);
