INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1934, 'Document PeÈ™tera F1 din Piatra Lupului #9', 'Fisa tehnica echipare put - verticala nr. 348. Adancimea: 494 metri. Am instalat 444 spituri din otel inoxidabil. Distanta intre spituri: 178 metri. Lungimea corzii principale: 438 metri. Coarda de siguranta: 376 metri. Am montat 79 protectoare de franghie. Fractionarea se face la 421 metri de buza putului. Deviatia este la 7 metri sub fractionare. Am testat echiparea cu 354 coborari. Ultimul control al spiturilor: acum 27 luni.', 'doc_existing_c42_9.txt', 432, NULL, 'text_document', 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4533, 42, 'cave', 1934, 1775839976);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1935, 'Document PeÈ™tera F1 din Piatra Lupului #10', 'Nota de mentenanta balize - traseul 297. Am verificat 355 balize reflectorizante. Dintre acestea, 266 au fost inlocuite. Am adaugat 354 balize noi in zonele nemarcate. Distanta medie intre balize: 63 metri. Am folosit 306 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 164 metri cu lampa frontala. Am eliminat 295 marcaje vechi si confuze. Traseul total balizat: 316 metri. Urmatoarea verificare: peste 373 luni. Materialul consumat: 287 benzi reflectorizante.', 'doc_existing_c42_10.txt', 484, NULL, 'text_document', 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4534, 42, 'cave', 1935, 1775839976);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4535, 2604, 'cave_place', 1935, 1775839976);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1936, 'Document PeÈ™tera F1 din Piatra Lupului #11', 'Raport geologic - profil 23. Stratele de calcar apartin etajului 208. Grosimea medie a stratelor este de 87 centimetri. Fisurile tectonice au un azimut predominant de 155 grade. Am recoltat 357 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 234 procente. Concretii de aragonita au fost gasite la cota 485. Varsta estimata a speleothemelor: 156 mii de ani. Depozitele clastice au o grosime de 381 centimetri. Am identificat 343 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 134 metri. Analiza XRD confirma 425 faze minerale distincte. Sectorul analizat are o lungime de 153 metri. Am realizat 391 profile transversale ale galeriei. Cutele vizibile au amplitudini de 400 centimetri.', 'doc_existing_c42_11.txt', 728, NULL, 'text_document', 1775839976);
