INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1937, 'Document PeÈ™tera F1 din Piatra Lupului #12', 'Studiu speleogenetic - sectorul 416. Am analizat 292 probe de calcar sub microscop. Varsta estimata a galeriei: 232 milioane de ani. Am identificat 109 faze de speleogeneza. Nivelul freatic actual este la 196 metri adancime. Am corelat cu 55 alte pesteri din zona. Porozitatea medie a rocii: 275 procente. Am realizat 263 sectiuni subtiri din probe. Studiul va fi publicat in volumul 420 al buletinului. Am colaborat cu 405 geologi specialisti.', 'doc_existing_c42_12.txt', 444, NULL, 'text_document', 1775839976);
