INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1939, 'Document PeÈ™tera F1 din Piatra Lupului #14', 'Raport conservare patrimoniu - obiectiv 326. Am evaluat starea a 306 inscriptii istorice. Dintre acestea, 480 necesita interventie urgenta. Am curatat 481 metri patrati de graffiti modern. Am instalat 111 panouri informative la intrare. Bariera de protectie acopera 308 metri liniari. Am documentat 194 urme de vandalism. Raportul a fost transmis autoritatilor locale in 312 exemplare. Am propus clasificarea a 81 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 474 persoane simultan. Am instruit 431 ghizi locali. Costul estimat al lucrarilor: 191 lei. Termenul de finalizare: 329 luni.', 'doc_existing_c42_14.txt', 605, NULL, 'text_document', 1775839976);
