INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1949, 'Document PeÈ™tera F2 din Piatra Lupului #7', 'Evidenta resurse hidrologice - punctul 53. Debitul mediu masurat: 19 litri pe secunda. Am efectuat 331 masuratori in perioade diferite. Temperatura apei: 94 grade Celsius, constanta. pH-ul masurat: 88 unitati. Conductivitatea electrica: 359 microsiemensi. Am injectat 156 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 213 ore. Distanta estimata: 330 metri de conducte carstice. Nivelul maxim in sezonul ploios: 431 centimetri peste normal. Am monitorizat 446 izvoare din bazin. Volumul estimat al lacului subteran: 138 metri cubi.', 'doc_existing_c43_7.txt', 545, NULL, 'text_document', 1775839976);
