INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1964, 'Document PeÈ™tera F4 din Piatra Lupului #2', 'Fisa tehnica echipare put - verticala nr. 111. Adancimea: 465 metri. Am instalat 416 spituri din otel inoxidabil. Distanta intre spituri: 54 metri. Lungimea corzii principale: 337 metri. Coarda de siguranta: 200 metri. Am montat 402 protectoare de franghie. Fractionarea se face la 236 metri de buza putului. Deviatia este la 16 metri sub fractionare. Am testat echiparea cu 500 coborari. Ultimul control al spiturilor: acum 487 luni.', 'doc_existing_c45_2.txt', 434, NULL, 'text_document', 1775839977);
