INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1966, 'Document PeÈ™tera F4 din Piatra Lupului #4', 'Evaluare risc - sectorul 123. Am identificat 392 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 150 centimetri. Nivelul apei poate creste cu 91 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 212 metri. Am instalat 6 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 276 minute. Echipamentul de prim ajutor este pozitionat la statia 247. Am testat comunicarea radio in 177 puncte critice. Semnalul radio este pierdut dupa 262 metri de la intrare. Am recomandat echipa minima de 477 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 295 ore. Protocoalele de securitate au fost revizuite de 130 ori anul acesta. Ultimul incident a avut loc cu 100 luni in urma. Am efectuat 255 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 407.', 'doc_existing_c45_4.txt', 888, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4608, 45, 'cave', 1966, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1967, 'Document PeÈ™tera F4 din Piatra Lupului #5', 'Evidenta resurse hidrologice - punctul 413. Debitul mediu masurat: 78 litri pe secunda. Am efectuat 312 masuratori in perioade diferite. Temperatura apei: 25 grade Celsius, constanta. pH-ul masurat: 273 unitati. Conductivitatea electrica: 393 microsiemensi. Am injectat 294 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 198 ore. Distanta estimata: 249 metri de conducte carstice. Nivelul maxim in sezonul ploios: 368 centimetri peste normal. Am monitorizat 395 izvoare din bazin. Volumul estimat al lacului subteran: 103 metri cubi.', 'doc_existing_c45_5.txt', 547, NULL, 'text_document', 1775839977);
