INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1971, 'Document PeÈ™tera F4 din Piatra Lupului #9', 'Raport climatologic subteran - statia 14. Senzorul a inregistrat 222 cicluri complete de temperatura. Temperatura medie anuala: 341 grade Celsius. Amplitudinea termica maxima: 60 grade. Umiditatea relativa medie: 472 procente. Concentratia de CO2: 374 ppm. Curentul de aer maxim masurat: 258 metri pe secunda. Directia predominanta a curentului: sector 378. Datalogerul a functionat 208 zile fara intrerupere. Am descarcat 352 megabytes de date brute. Presiunea barometrica la intrare: 335 mbar. Evaporarea masurata: 248 milimetri pe luna. Am comparat datele cu 58 statii meteorologice de suprafata. Raportul complet include 371 grafice si tabele. Monitorizarea continua de 351 luni confirma stabilitatea climatica.', 'doc_existing_c45_9.txt', 715, NULL, 'text_document', 1775839977);
