INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1973, 'Document PeÈ™tera F4 din Piatra Lupului #11', 'Studiu speleogenetic - sectorul 268. Am analizat 147 probe de calcar sub microscop. Varsta estimata a galeriei: 394 milioane de ani. Am identificat 136 faze de speleogeneza. Nivelul freatic actual este la 496 metri adancime. Am corelat cu 213 alte pesteri din zona. Porozitatea medie a rocii: 467 procente. Am realizat 317 sectiuni subtiri din probe. Studiul va fi publicat in volumul 354 al buletinului. Am colaborat cu 390 geologi specialisti.', 'doc_existing_c45_11.txt', 445, NULL, 'text_document', 1775839977);
