INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4649, 46, 'cave', 1983, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1984, 'Document PeÈ™tera F5 din Piatra Lupului #8', 'Studiu speleogenetic - sectorul 66. Am analizat 420 probe de calcar sub microscop. Varsta estimata a galeriei: 281 milioane de ani. Am identificat 433 faze de speleogeneza. Nivelul freatic actual este la 20 metri adancime. Am corelat cu 50 alte pesteri din zona. Porozitatea medie a rocii: 99 procente. Am realizat 445 sectiuni subtiri din probe. Studiul va fi publicat in volumul 27 al buletinului. Am colaborat cu 51 geologi specialisti.', 'doc_existing_c46_8.txt', 439, NULL, 'text_document', 1775839977);
