INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1985, 'Document PeÈ™tera F5 din Piatra Lupului #9', 'Proces verbal intalnire club - sedinta nr. 328. Au participat 425 membri. Am discutat 288 puncte pe ordinea de zi. S-a aprobat bugetul de 107 lei pentru trimestrul urmator. Am planificat 422 expeditii in urmatoarele luni. S-au inscris 384 membri noi. Am evaluat 49 rapoarte de explorare. S-a votat achizitionarea de echipament in valoare de 225 lei. Urmatoarea sedinta: peste 202 saptamani. Am desemnat 122 responsabili pentru proiecte.', 'doc_existing_c46_9.txt', 436, NULL, 'text_document', 1775839977);
