INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1994, 'Document PeÈ™tera G1 din Piatra Lupului #1', 'Fisa tehnica echipare put - verticala nr. 435. Adancimea: 14 metri. Am instalat 291 spituri din otel inoxidabil. Distanta intre spituri: 261 metri. Lungimea corzii principale: 15 metri. Coarda de siguranta: 348 metri. Am montat 48 protectoare de franghie. Fractionarea se face la 43 metri de buza putului. Deviatia este la 172 metri sub fractionare. Am testat echiparea cu 415 coborari. Ultimul control al spiturilor: acum 447 luni.', 'doc_existing_c47_1.txt', 432, NULL, 'text_document', 1775839977);
