INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (1996, 'Document PeÈ™tera G2 din Piatra Lupului #1', 'Raport conservare patrimoniu - obiectiv 242. Am evaluat starea a 268 inscriptii istorice. Dintre acestea, 164 necesita interventie urgenta. Am curatat 61 metri patrati de graffiti modern. Am instalat 126 panouri informative la intrare. Bariera de protectie acopera 452 metri liniari. Am documentat 301 urme de vandalism. Raportul a fost transmis autoritatilor locale in 235 exemplare. Am propus clasificarea a 464 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 366 persoane simultan. Am instruit 356 ghizi locali. Costul estimat al lucrarilor: 337 lei. Termenul de finalizare: 39 luni.', 'doc_existing_c48_1.txt', 604, NULL, 'text_document', 1775839977);
