INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2020, 'Document PeÈ™tera G3 din Piatra Lupului #7', 'Fisa tehnica echipare put - verticala nr. 268. Adancimea: 390 metri. Am instalat 268 spituri din otel inoxidabil. Distanta intre spituri: 168 metri. Lungimea corzii principale: 240 metri. Coarda de siguranta: 368 metri. Am montat 234 protectoare de franghie. Fractionarea se face la 144 metri de buza putului. Deviatia este la 193 metri sub fractionare. Am testat echiparea cu 184 coborari. Ultimul control al spiturilor: acum 478 luni.', 'doc_existing_c49_7.txt', 436, NULL, 'text_document', 1775839977);
