INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2044, 'Document PeÈ™tera H1 din Piatra Lupului #1', 'Evidenta resurse hidrologice - punctul 324. Debitul mediu masurat: 481 litri pe secunda. Am efectuat 47 masuratori in perioade diferite. Temperatura apei: 111 grade Celsius, constanta. pH-ul masurat: 302 unitati. Conductivitatea electrica: 92 microsiemensi. Am injectat 149 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 222 ore. Distanta estimata: 264 metri de conducte carstice. Nivelul maxim in sezonul ploios: 155 centimetri peste normal. Am monitorizat 6 izvoare din bazin. Volumul estimat al lacului subteran: 156 metri cubi.', 'doc_existing_c50_1.txt', 545, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4795, 50, 'cave', 2044, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4796, 229, 'cave_area', 2044, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4797, 3150, 'cave_place', 2044, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2045, 'Document PeÈ™tera H1 din Piatra Lupului #2', 'Raport geologic - profil 444. Stratele de calcar apartin etajului 435. Grosimea medie a stratelor este de 166 centimetri. Fisurile tectonice au un azimut predominant de 89 grade. Am recoltat 147 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 176 procente. Concretii de aragonita au fost gasite la cota 157. Varsta estimata a speleothemelor: 38 mii de ani. Depozitele clastice au o grosime de 160 centimetri. Am identificat 453 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 160 metri. Analiza XRD confirma 156 faze minerale distincte. Sectorul analizat are o lungime de 65 metri. Am realizat 320 profile transversale ale galeriei. Cutele vizibile au amplitudini de 291 centimetri.', 'doc_existing_c50_2.txt', 727, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4798, 50, 'cave', 2045, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4799, 3124, 'cave_place', 2045, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2046, 'Document PeÈ™tera H1 din Piatra Lupului #3', 'Raport geologic - profil 320. Stratele de calcar apartin etajului 136. Grosimea medie a stratelor este de 375 centimetri. Fisurile tectonice au un azimut predominant de 235 grade. Am recoltat 349 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 15 procente. Concretii de aragonita au fost gasite la cota 404. Varsta estimata a speleothemelor: 150 mii de ani. Depozitele clastice au o grosime de 377 centimetri. Am identificat 431 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 264 metri. Analiza XRD confirma 252 faze minerale distincte. Sectorul analizat are o lungime de 42 metri. Am realizat 27 profile transversale ale galeriei. Cutele vizibile au amplitudini de 57 centimetri.', 'doc_existing_c50_3.txt', 726, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4800, 50, 'cave', 2046, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2047, 'Document PeÈ™tera H1 din Piatra Lupului #4', 'Evidenta resurse hidrologice - punctul 258. Debitul mediu masurat: 234 litri pe secunda. Am efectuat 341 masuratori in perioade diferite. Temperatura apei: 82 grade Celsius, constanta. pH-ul masurat: 239 unitati. Conductivitatea electrica: 291 microsiemensi. Am injectat 52 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 146 ore. Distanta estimata: 40 metri de conducte carstice. Nivelul maxim in sezonul ploios: 260 centimetri peste normal. Am monitorizat 104 izvoare din bazin. Volumul estimat al lacului subteran: 140 metri cubi.', 'doc_existing_c50_4.txt', 546, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4801, 50, 'cave', 2047, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4802, 229, 'cave_area', 2047, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4803, 3134, 'cave_place', 2047, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2048, 'Document PeÈ™tera H1 din Piatra Lupului #5', 'Studiu speleogenetic - sectorul 22. Am analizat 168 probe de calcar sub microscop. Varsta estimata a galeriei: 414 milioane de ani. Am identificat 258 faze de speleogeneza. Nivelul freatic actual este la 389 metri adancime. Am corelat cu 82 alte pesteri din zona. Porozitatea medie a rocii: 430 procente. Am realizat 182 sectiuni subtiri din probe. Studiul va fi publicat in volumul 273 al buletinului. Am colaborat cu 388 geologi specialisti.', 'doc_existing_c50_5.txt', 443, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4804, 50, 'cave', 2048, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2049, 'Document PeÈ™tera H1 din Piatra Lupului #6', 'Proces verbal intalnire club - sedinta nr. 82. Au participat 411 membri. Am discutat 487 puncte pe ordinea de zi. S-a aprobat bugetul de 412 lei pentru trimestrul urmator. Am planificat 481 expeditii in urmatoarele luni. S-au inscris 478 membri noi. Am evaluat 465 rapoarte de explorare. S-a votat achizitionarea de echipament in valoare de 495 lei. Urmatoarea sedinta: peste 347 saptamani. Am desemnat 192 responsabili pentru proiecte.', 'doc_existing_c50_6.txt', 436, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4805, 50, 'cave', 2049, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4806, 229, 'cave_area', 2049, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4807, 3149, 'cave_place', 2049, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2050, 'Document PeÈ™tera H1 din Piatra Lupului #7', 'Studiu speleogenetic - sectorul 195. Am analizat 96 probe de calcar sub microscop. Varsta estimata a galeriei: 39 milioane de ani. Am identificat 433 faze de speleogeneza. Nivelul freatic actual este la 227 metri adancime. Am corelat cu 393 alte pesteri din zona. Porozitatea medie a rocii: 194 procente. Am realizat 383 sectiuni subtiri din probe. Studiul va fi publicat in volumul 119 al buletinului. Am colaborat cu 231 geologi specialisti.', 'doc_existing_c50_7.txt', 443, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4808, 50, 'cave', 2050, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2051, 'Document PeÈ™tera H1 din Piatra Lupului #8', 'Raport climatologic subteran - statia 115. Senzorul a inregistrat 232 cicluri complete de temperatura. Temperatura medie anuala: 443 grade Celsius. Amplitudinea termica maxima: 248 grade. Umiditatea relativa medie: 164 procente. Concentratia de CO2: 329 ppm. Curentul de aer maxim masurat: 319 metri pe secunda. Directia predominanta a curentului: sector 130. Datalogerul a functionat 15 zile fara intrerupere. Am descarcat 431 megabytes de date brute. Presiunea barometrica la intrare: 244 mbar. Evaporarea masurata: 308 milimetri pe luna. Am comparat datele cu 349 statii meteorologice de suprafata. Raportul complet include 162 grafice si tabele. Monitorizarea continua de 253 luni confirma stabilitatea climatica.', 'doc_existing_c50_8.txt', 717, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4809, 50, 'cave', 2051, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4810, 3129, 'cave_place', 2051, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2052, 'Document PeÈ™tera H1 din Piatra Lupului #9', 'Nota de mentenanta balize - traseul 162. Am verificat 143 balize reflectorizante. Dintre acestea, 498 au fost inlocuite. Am adaugat 495 balize noi in zonele nemarcate. Distanta medie intre balize: 465 metri. Am folosit 299 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 320 metri cu lampa frontala. Am eliminat 6 marcaje vechi si confuze. Traseul total balizat: 86 metri. Urmatoarea verificare: peste 41 luni. Materialul consumat: 465 benzi reflectorizante.', 'doc_existing_c50_9.txt', 481, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4811, 50, 'cave', 2052, 1775839977);
