INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2075, 'Document PeÈ™tera H3 din Piatra Lupului #3', 'Proces verbal intalnire club - sedinta nr. 290. Au participat 487 membri. Am discutat 391 puncte pe ordinea de zi. S-a aprobat bugetul de 169 lei pentru trimestrul urmator. Am planificat 478 expeditii in urmatoarele luni. S-au inscris 74 membri noi. Am evaluat 271 rapoarte de explorare. S-a votat achizitionarea de echipament in valoare de 382 lei. Urmatoarea sedinta: peste 494 saptamani. Am desemnat 89 responsabili pentru proiecte.', 'doc_existing_c52_3.txt', 435, NULL, 'text_document', 1775839977);
