INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2095, 'Document PeÈ™tera H4 din Piatra Lupului #1', 'Raport climatologic subteran - statia 318. Senzorul a inregistrat 29 cicluri complete de temperatura. Temperatura medie anuala: 363 grade Celsius. Amplitudinea termica maxima: 319 grade. Umiditatea relativa medie: 462 procente. Concentratia de CO2: 189 ppm. Curentul de aer maxim masurat: 92 metri pe secunda. Directia predominanta a curentului: sector 244. Datalogerul a functionat 464 zile fara intrerupere. Am descarcat 420 megabytes de date brute. Presiunea barometrica la intrare: 163 mbar. Evaporarea masurata: 362 milimetri pe luna. Am comparat datele cu 350 statii meteorologice de suprafata. Raportul complet include 103 grafice si tabele. Monitorizarea continua de 298 luni confirma stabilitatea climatica.', 'doc_existing_c53_1.txt', 716, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4909, 53, 'cave', 2095, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4910, 3347, 'cave_place', 2095, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2096, 'Document PeÈ™tera H4 din Piatra Lupului #2', 'Evidenta resurse hidrologice - punctul 346. Debitul mediu masurat: 444 litri pe secunda. Am efectuat 186 masuratori in perioade diferite. Temperatura apei: 498 grade Celsius, constanta. pH-ul masurat: 124 unitati. Conductivitatea electrica: 50 microsiemensi. Am injectat 154 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 356 ore. Distanta estimata: 430 metri de conducte carstice. Nivelul maxim in sezonul ploios: 117 centimetri peste normal. Am monitorizat 371 izvoare din bazin. Volumul estimat al lacului subteran: 419 metri cubi.', 'doc_existing_c53_2.txt', 548, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4911, 53, 'cave', 2096, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4912, 241, 'cave_area', 2096, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2097, 'Document PeÈ™tera H4 din Piatra Lupului #3', 'Fisa tehnica echipare put - verticala nr. 187. Adancimea: 3 metri. Am instalat 163 spituri din otel inoxidabil. Distanta intre spituri: 457 metri. Lungimea corzii principale: 63 metri. Coarda de siguranta: 109 metri. Am montat 431 protectoare de franghie. Fractionarea se face la 379 metri de buza putului. Deviatia este la 76 metri sub fractionare. Am testat echiparea cu 29 coborari. Ultimul control al spiturilor: acum 85 luni.', 'doc_existing_c53_3.txt', 430, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4913, 53, 'cave', 2097, 1775839977);
