INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2098, 'Document PeÈ™tera H4 din Piatra Lupului #4', 'Studiu speleogenetic - sectorul 10. Am analizat 130 probe de calcar sub microscop. Varsta estimata a galeriei: 8 milioane de ani. Am identificat 434 faze de speleogeneza. Nivelul freatic actual este la 30 metri adancime. Am corelat cu 63 alte pesteri din zona. Porozitatea medie a rocii: 346 procente. Am realizat 280 sectiuni subtiri din probe. Studiul va fi publicat in volumul 379 al buletinului. Am colaborat cu 297 geologi specialisti.', 'doc_existing_c53_4.txt', 440, NULL, 'text_document', 1775839977);
