INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2099, 'Document PeÈ™tera H4 din Piatra Lupului #5', 'Raport climatologic subteran - statia 355. Senzorul a inregistrat 46 cicluri complete de temperatura. Temperatura medie anuala: 66 grade Celsius. Amplitudinea termica maxima: 110 grade. Umiditatea relativa medie: 46 procente. Concentratia de CO2: 495 ppm. Curentul de aer maxim masurat: 288 metri pe secunda. Directia predominanta a curentului: sector 167. Datalogerul a functionat 263 zile fara intrerupere. Am descarcat 262 megabytes de date brute. Presiunea barometrica la intrare: 109 mbar. Evaporarea masurata: 46 milimetri pe luna. Am comparat datele cu 3 statii meteorologice de suprafata. Raportul complet include 332 grafice si tabele. Monitorizarea continua de 484 luni confirma stabilitatea climatica.', 'doc_existing_c53_5.txt', 712, NULL, 'text_document', 1775839977);
