INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2102, 'Document PeÈ™tera H4 din Piatra Lupului #8', 'Raport climatologic subteran - statia 341. Senzorul a inregistrat 459 cicluri complete de temperatura. Temperatura medie anuala: 220 grade Celsius. Amplitudinea termica maxima: 428 grade. Umiditatea relativa medie: 335 procente. Concentratia de CO2: 312 ppm. Curentul de aer maxim masurat: 218 metri pe secunda. Directia predominanta a curentului: sector 8. Datalogerul a functionat 412 zile fara intrerupere. Am descarcat 338 megabytes de date brute. Presiunea barometrica la intrare: 373 mbar. Evaporarea masurata: 396 milimetri pe luna. Am comparat datele cu 489 statii meteorologice de suprafata. Raportul complet include 121 grafice si tabele. Monitorizarea continua de 52 luni confirma stabilitatea climatica.', 'doc_existing_c53_8.txt', 715, NULL, 'text_document', 1775839977);
