INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2121, 'Document PeÈ™tera din Dealul Glimea #1', 'Nota de mentenanta balize - traseul 216. Am verificat 390 balize reflectorizante. Dintre acestea, 400 au fost inlocuite. Am adaugat 66 balize noi in zonele nemarcate. Distanta medie intre balize: 233 metri. Am folosit 473 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 80 metri cu lampa frontala. Am eliminat 249 marcaje vechi si confuze. Traseul total balizat: 360 metri. Urmatoarea verificare: peste 178 luni. Materialul consumat: 54 benzi reflectorizante.', 'doc_existing_c54_1.txt', 482, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4972, 54, 'cave', 2121, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2122, 'Document PeÈ™tera din Dealul Glimea #2', 'Evidenta resurse hidrologice - punctul 456. Debitul mediu masurat: 241 litri pe secunda. Am efectuat 255 masuratori in perioade diferite. Temperatura apei: 434 grade Celsius, constanta. pH-ul masurat: 88 unitati. Conductivitatea electrica: 149 microsiemensi. Am injectat 391 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 410 ore. Distanta estimata: 429 metri de conducte carstice. Nivelul maxim in sezonul ploios: 472 centimetri peste normal. Am monitorizat 487 izvoare din bazin. Volumul estimat al lacului subteran: 302 metri cubi.', 'doc_existing_c54_2.txt', 548, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (4973, 54, 'cave', 2122, 1775839977);
