INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2135, 'Document PeÈ™tera nr. 1 de la FaÈ›a Cerbului #1', 'Raport conservare patrimoniu - obiectiv 347. Am evaluat starea a 275 inscriptii istorice. Dintre acestea, 150 necesita interventie urgenta. Am curatat 275 metri patrati de graffiti modern. Am instalat 244 panouri informative la intrare. Bariera de protectie acopera 328 metri liniari. Am documentat 336 urme de vandalism. Raportul a fost transmis autoritatilor locale in 299 exemplare. Am propus clasificarea a 452 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 100 persoane simultan. Am instruit 463 ghizi locali. Costul estimat al lucrarilor: 1 lei. Termenul de finalizare: 87 luni.', 'doc_existing_c55_1.txt', 603, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5006, 55, 'cave', 2135, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5007, 3461, 'cave_place', 2135, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2136, 'Document PeÈ™tera nr. 1 de la FaÈ›a Cerbului #2', 'Raport geologic - profil 489. Stratele de calcar apartin etajului 86. Grosimea medie a stratelor este de 494 centimetri. Fisurile tectonice au un azimut predominant de 280 grade. Am recoltat 458 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 417 procente. Concretii de aragonita au fost gasite la cota 112. Varsta estimata a speleothemelor: 114 mii de ani. Depozitele clastice au o grosime de 451 centimetri. Am identificat 152 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 353 metri. Analiza XRD confirma 269 faze minerale distincte. Sectorul analizat are o lungime de 126 metri. Am realizat 93 profile transversale ale galeriei. Cutele vizibile au amplitudini de 55 centimetri.', 'doc_existing_c55_2.txt', 727, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5008, 55, 'cave', 2136, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5009, 249, 'cave_area', 2136, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5010, 3464, 'cave_place', 2136, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2137, 'Document PeÈ™tera nr. 1 de la FaÈ›a Cerbului #3', 'Evidenta resurse hidrologice - punctul 312. Debitul mediu masurat: 11 litri pe secunda. Am efectuat 386 masuratori in perioade diferite. Temperatura apei: 470 grade Celsius, constanta. pH-ul masurat: 162 unitati. Conductivitatea electrica: 337 microsiemensi. Am injectat 10 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 440 ore. Distanta estimata: 468 metri de conducte carstice. Nivelul maxim in sezonul ploios: 369 centimetri peste normal. Am monitorizat 24 izvoare din bazin. Volumul estimat al lacului subteran: 162 metri cubi.', 'doc_existing_c55_3.txt', 546, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5011, 55, 'cave', 2137, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2138, 'Document PeÈ™tera nr. 1 de la FaÈ›a Cerbului #4', 'Raport conservare patrimoniu - obiectiv 26. Am evaluat starea a 253 inscriptii istorice. Dintre acestea, 412 necesita interventie urgenta. Am curatat 86 metri patrati de graffiti modern. Am instalat 376 panouri informative la intrare. Bariera de protectie acopera 9 metri liniari. Am documentat 496 urme de vandalism. Raportul a fost transmis autoritatilor locale in 349 exemplare. Am propus clasificarea a 231 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 279 persoane simultan. Am instruit 483 ghizi locali. Costul estimat al lucrarilor: 240 lei. Termenul de finalizare: 179 luni.', 'doc_existing_c55_4.txt', 602, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5012, 55, 'cave', 2138, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5013, 249, 'cave_area', 2138, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5014, 3469, 'cave_place', 2138, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2139, 'Document PeÈ™tera nr. 1 de la FaÈ›a Cerbului #5', 'Studiu speleogenetic - sectorul 290. Am analizat 327 probe de calcar sub microscop. Varsta estimata a galeriei: 472 milioane de ani. Am identificat 194 faze de speleogeneza. Nivelul freatic actual este la 227 metri adancime. Am corelat cu 115 alte pesteri din zona. Porozitatea medie a rocii: 311 procente. Am realizat 283 sectiuni subtiri din probe. Studiul va fi publicat in volumul 457 al buletinului. Am colaborat cu 271 geologi specialisti.', 'doc_existing_c55_5.txt', 445, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5015, 55, 'cave', 2139, 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5016, 3496, 'cave_place', 2139, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2140, 'Document PeÈ™tera nr. 1 de la FaÈ›a Cerbului #6', 'Raport geologic - profil 495. Stratele de calcar apartin etajului 400. Grosimea medie a stratelor este de 154 centimetri. Fisurile tectonice au un azimut predominant de 187 grade. Am recoltat 71 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 395 procente. Concretii de aragonita au fost gasite la cota 208. Varsta estimata a speleothemelor: 218 mii de ani. Depozitele clastice au o grosime de 146 centimetri. Am identificat 369 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 306 metri. Analiza XRD confirma 285 faze minerale distincte. Sectorul analizat are o lungime de 135 metri. Am realizat 472 profile transversale ale galeriei. Cutele vizibile au amplitudini de 243 centimetri.', 'doc_existing_c55_6.txt', 729, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5017, 55, 'cave', 2140, 1775839977);
