INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5019, 3467, 'cave_place', 2140, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2141, 'Document PeÈ™tera nr. 1 de la FaÈ›a Cerbului #7', 'Raport conservare patrimoniu - obiectiv 269. Am evaluat starea a 460 inscriptii istorice. Dintre acestea, 372 necesita interventie urgenta. Am curatat 64 metri patrati de graffiti modern. Am instalat 227 panouri informative la intrare. Bariera de protectie acopera 423 metri liniari. Am documentat 185 urme de vandalism. Raportul a fost transmis autoritatilor locale in 321 exemplare. Am propus clasificarea a 87 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 24 persoane simultan. Am instruit 393 ghizi locali. Costul estimat al lucrarilor: 138 lei. Termenul de finalizare: 500 luni.', 'doc_existing_c55_7.txt', 603, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5020, 55, 'cave', 2141, 1775839977);
