INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2142, 'Document PeÈ™tera nr. 1 de la FaÈ›a Cerbului #8', 'Raport conservare patrimoniu - obiectiv 99. Am evaluat starea a 116 inscriptii istorice. Dintre acestea, 272 necesita interventie urgenta. Am curatat 103 metri patrati de graffiti modern. Am instalat 324 panouri informative la intrare. Bariera de protectie acopera 158 metri liniari. Am documentat 428 urme de vandalism. Raportul a fost transmis autoritatilor locale in 330 exemplare. Am propus clasificarea a 78 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 235 persoane simultan. Am instruit 361 ghizi locali. Costul estimat al lucrarilor: 476 lei. Termenul de finalizare: 467 luni.', 'doc_existing_c55_8.txt', 604, NULL, 'text_document', 1775839977);
