INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2144, 'Document PeÈ™tera nr. 1 de la FaÈ›a Cerbului #10', 'Raport conservare patrimoniu - obiectiv 380. Am evaluat starea a 157 inscriptii istorice. Dintre acestea, 17 necesita interventie urgenta. Am curatat 223 metri patrati de graffiti modern. Am instalat 448 panouri informative la intrare. Bariera de protectie acopera 250 metri liniari. Am documentat 134 urme de vandalism. Raportul a fost transmis autoritatilor locale in 456 exemplare. Am propus clasificarea a 99 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 434 persoane simultan. Am instruit 240 ghizi locali. Costul estimat al lucrarilor: 87 lei. Termenul de finalizare: 459 luni.', 'doc_existing_c55_10.txt', 603, NULL, 'text_document', 1775839977);
