INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2147, 'Document PeÈ™tera nr. 1 de la FaÈ›a Cerbului #13', 'Evidenta resurse hidrologice - punctul 164. Debitul mediu masurat: 421 litri pe secunda. Am efectuat 240 masuratori in perioade diferite. Temperatura apei: 455 grade Celsius, constanta. pH-ul masurat: 94 unitati. Conductivitatea electrica: 115 microsiemensi. Am injectat 448 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 50 ore. Distanta estimata: 433 metri de conducte carstice. Nivelul maxim in sezonul ploios: 50 centimetri peste normal. Am monitorizat 290 izvoare din bazin. Volumul estimat al lacului subteran: 397 metri cubi.', 'doc_existing_c55_13.txt', 546, NULL, 'text_document', 1775839977);
