INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2162, 'Document PeÈ™tera nr. 2 de la FaÈ›a Cerbului #4', 'Fisa tehnica echipare put - verticala nr. 128. Adancimea: 62 metri. Am instalat 288 spituri din otel inoxidabil. Distanta intre spituri: 395 metri. Lungimea corzii principale: 130 metri. Coarda de siguranta: 306 metri. Am montat 106 protectoare de franghie. Fractionarea se face la 140 metri de buza putului. Deviatia este la 296 metri sub fractionare. Am testat echiparea cu 433 coborari. Ultimul control al spiturilor: acum 328 luni.', 'doc_existing_c56_4.txt', 435, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5071, 56, 'cave', 2162, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2163, 'Document PeÈ™tera nr. 2 de la FaÈ›a Cerbului #5', 'Studiu speleogenetic - sectorul 345. Am analizat 169 probe de calcar sub microscop. Varsta estimata a galeriei: 352 milioane de ani. Am identificat 359 faze de speleogeneza. Nivelul freatic actual este la 204 metri adancime. Am corelat cu 152 alte pesteri din zona. Porozitatea medie a rocii: 13 procente. Am realizat 399 sectiuni subtiri din probe. Studiul va fi publicat in volumul 440 al buletinului. Am colaborat cu 140 geologi specialisti.', 'doc_existing_c56_5.txt', 444, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5072, 56, 'cave', 2163, 1775839977);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2164, 'Document PeÈ™tera nr. 2 de la FaÈ›a Cerbului #6', 'Raport climatologic subteran - statia 374. Senzorul a inregistrat 42 cicluri complete de temperatura. Temperatura medie anuala: 480 grade Celsius. Amplitudinea termica maxima: 353 grade. Umiditatea relativa medie: 454 procente. Concentratia de CO2: 170 ppm. Curentul de aer maxim masurat: 234 metri pe secunda. Directia predominanta a curentului: sector 86. Datalogerul a functionat 464 zile fara intrerupere. Am descarcat 194 megabytes de date brute. Presiunea barometrica la intrare: 120 mbar. Evaporarea masurata: 456 milimetri pe luna. Am comparat datele cu 281 statii meteorologice de suprafata. Raportul complet include 211 grafice si tabele. Monitorizarea continua de 161 luni confirma stabilitatea climatica.', 'doc_existing_c56_6.txt', 716, NULL, 'text_document', 1775839977);
