INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2167, 'Document PeÈ™tera nr. 2 de la FaÈ›a Cerbului #9', 'Proces verbal intalnire club - sedinta nr. 62. Au participat 196 membri. Am discutat 466 puncte pe ordinea de zi. S-a aprobat bugetul de 76 lei pentru trimestrul urmator. Am planificat 35 expeditii in urmatoarele luni. S-au inscris 99 membri noi. Am evaluat 435 rapoarte de explorare. S-a votat achizitionarea de echipament in valoare de 363 lei. Urmatoarea sedinta: peste 374 saptamani. Am desemnat 269 responsabili pentru proiecte.', 'doc_existing_c56_9.txt', 433, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5081, 56, 'cave', 2167, 1775839977);
