INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2195, 'Document Avenul nr. 3 din Poiana PleÈ™iÈ›a #4', 'Studiu speleogenetic - sectorul 251. Am analizat 102 probe de calcar sub microscop. Varsta estimata a galeriei: 353 milioane de ani. Am identificat 464 faze de speleogeneza. Nivelul freatic actual este la 452 metri adancime. Am corelat cu 40 alte pesteri din zona. Porozitatea medie a rocii: 86 procente. Am realizat 463 sectiuni subtiri din probe. Studiul va fi publicat in volumul 358 al buletinului. Am colaborat cu 436 geologi specialisti.', 'doc_existing_c57_4.txt', 443, NULL, 'text_document', 1775839977);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5151, 57, 'cave', 2195, 1775839977);
