INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2201, 'Document Avenul nr. 3 din Poiana PleÈ™iÈ›a #10', 'Evaluare risc - sectorul 483. Am identificat 229 zone cu risc de prabusire a plafonului. Blocurile instabile au dimensiuni de pana la 455 centimetri. Nivelul apei poate creste cu 175 metri in caz de precipitatii. Distanta de la intrare pana la prima zona de risc: 311 metri. Am instalat 363 indicatoare de avertizare reflectorizante. Evacuarea de urgenta dureaza estimativ 241 minute. Echipamentul de prim ajutor este pozitionat la statia 410. Am testat comunicarea radio in 169 puncte critice. Semnalul radio este pierdut dupa 370 metri de la intrare. Am recomandat echipa minima de 313 persoane pentru acest sector. Casca si lampa frontala trebuie verificate la fiecare 225 ore. Protocoalele de securitate au fost revizuite de 415 ori anul acesta. Ultimul incident a avut loc cu 228 luni in urma. Am efectuat 324 exercitii de evacuare. Planul de urgenta a fost actualizat la versiunea 388.', 'doc_existing_c57_10.txt', 891, NULL, 'text_document', 1775839977);
