INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2220, 'Document PeÈ™tera CaroleÈ™tilor #3', 'Fisa tehnica echipare put - verticala nr. 286. Adancimea: 149 metri. Am instalat 282 spituri din otel inoxidabil. Distanta intre spituri: 175 metri. Lungimea corzii principale: 41 metri. Coarda de siguranta: 151 metri. Am montat 184 protectoare de franghie. Fractionarea se face la 127 metri de buza putului. Deviatia este la 19 metri sub fractionare. Am testat echiparea cu 247 coborari. Ultimul control al spiturilor: acum 343 luni.', 'doc_existing_c58_3.txt', 434, NULL, 'text_document', 1775839978);
