INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2236, 'Document PeÈ™tera nr. 2 din Dealul Bulz #1', 'Nota de mentenanta balize - traseul 249. Am verificat 274 balize reflectorizante. Dintre acestea, 92 au fost inlocuite. Am adaugat 375 balize noi in zonele nemarcate. Distanta medie intre balize: 350 metri. Am folosit 53 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 458 metri cu lampa frontala. Am eliminat 274 marcaje vechi si confuze. Traseul total balizat: 116 metri. Urmatoarea verificare: peste 134 luni. Materialul consumat: 247 benzi reflectorizante.', 'doc_existing_c59_1.txt', 483, NULL, 'text_document', 1775839978);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5247, 59, 'cave', 2236, 1775839978);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2237, 'Document PeÈ™tera nr. 2 din Dealul Bulz #2', 'Nota de mentenanta balize - traseul 463. Am verificat 10 balize reflectorizante. Dintre acestea, 254 au fost inlocuite. Am adaugat 190 balize noi in zonele nemarcate. Distanta medie intre balize: 450 metri. Am folosit 25 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 201 metri cu lampa frontala. Am eliminat 321 marcaje vechi si confuze. Traseul total balizat: 355 metri. Urmatoarea verificare: peste 48 luni. Materialul consumat: 361 benzi reflectorizante.', 'doc_existing_c59_2.txt', 482, NULL, 'text_document', 1775839978);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5248, 59, 'cave', 2237, 1775839978);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5249, 3780, 'cave_place', 2237, 1775839978);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2238, 'Document PeÈ™tera nr. 2 din Dealul Bulz #3', 'Studiu speleogenetic - sectorul 252. Am analizat 288 probe de calcar sub microscop. Varsta estimata a galeriei: 350 milioane de ani. Am identificat 404 faze de speleogeneza. Nivelul freatic actual este la 175 metri adancime. Am corelat cu 129 alte pesteri din zona. Porozitatea medie a rocii: 364 procente. Am realizat 435 sectiuni subtiri din probe. Studiul va fi publicat in volumul 413 al buletinului. Am colaborat cu 328 geologi specialisti.', 'doc_existing_c59_3.txt', 445, NULL, 'text_document', 1775839978);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5250, 59, 'cave', 2238, 1775839978);
