INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2239, 'Document PeÈ™tera nr. 2 din Dealul Bulz #4', 'Evidenta resurse hidrologice - punctul 34. Debitul mediu masurat: 486 litri pe secunda. Am efectuat 296 masuratori in perioade diferite. Temperatura apei: 61 grade Celsius, constanta. pH-ul masurat: 70 unitati. Conductivitatea electrica: 400 microsiemensi. Am injectat 98 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 494 ore. Distanta estimata: 260 metri de conducte carstice. Nivelul maxim in sezonul ploios: 65 centimetri peste normal. Am monitorizat 263 izvoare din bazin. Volumul estimat al lacului subteran: 460 metri cubi.', 'doc_existing_c59_4.txt', 544, NULL, 'text_document', 1775839978);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5252, 59, 'cave', 2239, 1775839978);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5253, 3766, 'cave_place', 2239, 1775839978);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2240, 'Document PeÈ™tera nr. 2 din Dealul Bulz #5', 'Proces verbal intalnire club - sedinta nr. 412. Au participat 496 membri. Am discutat 258 puncte pe ordinea de zi. S-a aprobat bugetul de 248 lei pentru trimestrul urmator. Am planificat 370 expeditii in urmatoarele luni. S-au inscris 394 membri noi. Am evaluat 80 rapoarte de explorare. S-a votat achizitionarea de echipament in valoare de 50 lei. Urmatoarea sedinta: peste 371 saptamani. Am desemnat 439 responsabili pentru proiecte.', 'doc_existing_c59_5.txt', 435, NULL, 'text_document', 1775839978);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5254, 59, 'cave', 2240, 1775839978);
