INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2241, 'Document PeÈ™tera nr. 2 din Dealul Bulz #6', 'Studiu speleogenetic - sectorul 145. Am analizat 154 probe de calcar sub microscop. Varsta estimata a galeriei: 458 milioane de ani. Am identificat 252 faze de speleogeneza. Nivelul freatic actual este la 290 metri adancime. Am corelat cu 154 alte pesteri din zona. Porozitatea medie a rocii: 332 procente. Am realizat 25 sectiuni subtiri din probe. Studiul va fi publicat in volumul 492 al buletinului. Am colaborat cu 381 geologi specialisti.', 'doc_existing_c59_6.txt', 444, NULL, 'text_document', 1775839978);
