INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2242, 'Document PeÈ™tera nr. 2 din Dealul Bulz #7', 'Evidenta resurse hidrologice - punctul 327. Debitul mediu masurat: 429 litri pe secunda. Am efectuat 373 masuratori in perioade diferite. Temperatura apei: 268 grade Celsius, constanta. pH-ul masurat: 492 unitati. Conductivitatea electrica: 217 microsiemensi. Am injectat 63 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 4 ore. Distanta estimata: 335 metri de conducte carstice. Nivelul maxim in sezonul ploios: 110 centimetri peste normal. Am monitorizat 98 izvoare din bazin. Volumul estimat al lacului subteran: 393 metri cubi.', 'doc_existing_c59_7.txt', 545, NULL, 'text_document', 1775839978);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5259, 59, 'cave', 2242, 1775839978);
