INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2244, 'Document PeÈ™tera nr. 2 din Dealul Bulz #9', 'Raport climatologic subteran - statia 303. Senzorul a inregistrat 383 cicluri complete de temperatura. Temperatura medie anuala: 485 grade Celsius. Amplitudinea termica maxima: 82 grade. Umiditatea relativa medie: 320 procente. Concentratia de CO2: 410 ppm. Curentul de aer maxim masurat: 261 metri pe secunda. Directia predominanta a curentului: sector 23. Datalogerul a functionat 89 zile fara intrerupere. Am descarcat 383 megabytes de date brute. Presiunea barometrica la intrare: 76 mbar. Evaporarea masurata: 205 milimetri pe luna. Am comparat datele cu 438 statii meteorologice de suprafata. Raportul complet include 382 grafice si tabele. Monitorizarea continua de 15 luni confirma stabilitatea climatica.', 'doc_existing_c59_9.txt', 713, NULL, 'text_document', 1775839978);
