INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2248, 'Document PeÈ™tera nr. 2 din Dealul Bulz #13', 'Nota de mentenanta balize - traseul 205. Am verificat 131 balize reflectorizante. Dintre acestea, 322 au fost inlocuite. Am adaugat 137 balize noi in zonele nemarcate. Distanta medie intre balize: 137 metri. Am folosit 163 culori diferite conform codificarii. Vizibilitatea minima a balizelor: 215 metri cu lampa frontala. Am eliminat 43 marcaje vechi si confuze. Traseul total balizat: 199 metri. Urmatoarea verificare: peste 154 luni. Materialul consumat: 486 benzi reflectorizante.', 'doc_existing_c59_13.txt', 484, NULL, 'text_document', 1775839978);
