INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2250, 'Document PeÈ™tera nr. 2 din Dealul Bulz #15', 'Fisa tehnica echipare put - verticala nr. 389. Adancimea: 421 metri. Am instalat 115 spituri din otel inoxidabil. Distanta intre spituri: 159 metri. Lungimea corzii principale: 241 metri. Coarda de siguranta: 280 metri. Am montat 312 protectoare de franghie. Fractionarea se face la 499 metri de buza putului. Deviatia este la 383 metri sub fractionare. Am testat echiparea cu 360 coborari. Ultimul control al spiturilor: acum 494 luni.', 'doc_existing_c59_15.txt', 436, NULL, 'text_document', 1775839978);
