INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2268, 'Document PeÈ™tera "Hotel" #1', 'Studiu speleogenetic - sectorul 460. Am analizat 185 probe de calcar sub microscop. Varsta estimata a galeriei: 398 milioane de ani. Am identificat 246 faze de speleogeneza. Nivelul freatic actual este la 432 metri adancime. Am corelat cu 196 alte pesteri din zona. Porozitatea medie a rocii: 433 procente. Am realizat 278 sectiuni subtiri din probe. Studiul va fi publicat in volumul 59 al buletinului. Am colaborat cu 380 geologi specialisti.', 'doc_existing_c60_1.txt', 444, NULL, 'text_document', 1775839978);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5319, 60, 'cave', 2268, 1775839978);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5320, 3809, 'cave_place', 2268, 1775839978);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2269, 'Document PeÈ™tera "Hotel" #2', 'Evidenta resurse hidrologice - punctul 335. Debitul mediu masurat: 366 litri pe secunda. Am efectuat 305 masuratori in perioade diferite. Temperatura apei: 172 grade Celsius, constanta. pH-ul masurat: 26 unitati. Conductivitatea electrica: 379 microsiemensi. Am injectat 174 grame de trasor fluorescent. Trasorul a aparut la izvor dupa 23 ore. Distanta estimata: 247 metri de conducte carstice. Nivelul maxim in sezonul ploios: 426 centimetri peste normal. Am monitorizat 98 izvoare din bazin. Volumul estimat al lacului subteran: 476 metri cubi.', 'doc_existing_c60_2.txt', 546, NULL, 'text_document', 1775839978);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5321, 60, 'cave', 2269, 1775839978);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2270, 'Document PeÈ™tera "Hotel" #3', 'Raport geologic - profil 106. Stratele de calcar apartin etajului 210. Grosimea medie a stratelor este de 186 centimetri. Fisurile tectonice au un azimut predominant de 45 grade. Am recoltat 253 probe de roca pentru datarea izotopica. Continutul de CaCO3 depaseste 437 procente. Concretii de aragonita au fost gasite la cota 393. Varsta estimata a speleothemelor: 297 mii de ani. Depozitele clastice au o grosime de 127 centimetri. Am identificat 386 tipuri diferite de sedimente. Nivelul paleoclappei fosile este la cota 161 metri. Analiza XRD confirma 205 faze minerale distincte. Sectorul analizat are o lungime de 64 metri. Am realizat 58 profile transversale ale galeriei. Cutele vizibile au amplitudini de 210 centimetri.', 'doc_existing_c60_3.txt', 727, NULL, 'text_document', 1775839978);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5322, 60, 'cave', 2270, 1775839978);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5323, 269, 'cave_area', 2270, 1775839978);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5324, 3809, 'cave_place', 2270, 1775839978);
INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2271, 'Document PeÈ™tera "Hotel" #4', 'Raport conservare patrimoniu - obiectiv 47. Am evaluat starea a 407 inscriptii istorice. Dintre acestea, 402 necesita interventie urgenta. Am curatat 215 metri patrati de graffiti modern. Am instalat 135 panouri informative la intrare. Bariera de protectie acopera 207 metri liniari. Am documentat 260 urme de vandalism. Raportul a fost transmis autoritatilor locale in 331 exemplare. Am propus clasificarea a 417 formatiuni ca monument natural. Vizitele ghidate sunt limitate la 323 persoane simultan. Am instruit 264 ghizi locali. Costul estimat al lucrarilor: 59 lei. Termenul de finalizare: 116 luni.', 'doc_existing_c60_4.txt', 604, NULL, 'text_document', 1775839978);
INSERT INTO documentation_files_to_geofeatures (id, geofeature_id, geofeature_type, documentation_file_id, updated_at) VALUES (5325, 60, 'cave', 2271, 1775839978);
