INSERT INTO documentation_files (id, title, description, file_name, file_size, file_hash, file_type, created_at) VALUES (2293, 'Document PeÈ™tera nr. 1 din Bulz #3', 'Fisa tehnica echipare put - verticala nr. 143. Adancimea: 425 metri. Am instalat 368 spituri din otel inoxidabil. Distanta intre spituri: 126 metri. Lungimea corzii principale: 489 metri. Coarda de siguranta: 383 metri. Am montat 245 protectoare de franghie. Fractionarea se face la 157 metri de buza putului. Deviatia este la 13 metri sub fractionare. Am testat echiparea cu 306 coborari. Ultimul control al spiturilor: acum 401 luni.', 'doc_existing_c62_3.txt', 435, NULL, 'text_document', 1775839978);
